ScrollWorld:
    move.b  ($0015,A4),D0
    ; The purpose of this is to delay vertical scrolling.
    ; OW: once every two frames
    ; UW: once every four frames
    ; Horizontal scrolling happens every frame.
    andi.b #$03,D0
    moveq   #0,D3
    move.b  ($0010,A4),D3
    bne  _anon_z05_8
    andi.b #$01,D0
_anon_z05_8:
    move.b  ($00E6,A4),D1
    cmp.b   D1,D0
    beq.s  __far_z_05_0007
    jmp  ScrollWorldH
__far_z_05_0007:
    moveq   #8,D0
    move.b  ($0098,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    bne.s  __far_z_05_0008
    jmp  ScrollWorldDownOrH
__far_z_05_0008:
    ; then scroll up.
    ; Scrolling up starts from the top of NT 2 at $2800.
    ;
    subq.b  #1,($00E9,A4)
    move.b  ($0084,A4),D0
    cmpi.b  #$DD,D0
    bcc  _anon_z05_9
    move.b  #$08,D1
    addx.b  D1,D0   ; ADC #$08 (X flag = 6502 C)
    move.b  D0,($0084,A4)
_anon_z05_9:
    move.b  ($00E2,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$20,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$20
    eori    #$10,CCR  ; restore X = 6502 C
    move.b  D0,($00E2,A4)
    bcc  _anon_z05_10
    subq.b  #1,($0058,A4)
_anon_z05_10:
    cmpi.b  #$E0,D0
    bne  _L_z05_ScrollWorld_Exit
    move.b  ($0058,A4),D0
    cmpi.b  #$20,D0
    beq  _L_z05_ScrollWorld_LimitLow
    cmpi.b  #$27,D0
    bne  _L_z05_ScrollWorld_Exit
    ; VScroll address is $27E0. So, we rolled from the
    ; top of NT 2 to the last row of NT 0. Change the address
    ; to $23A0, the true last row of NT 0.
    moveq   #35,D0
    move.b  D0,($0058,A4)
    move.b  #$A0,D0
    move.b  D0,($00E2,A4)
    even
_L_z05_ScrollWorld_Exit:
    rts

    even
_L_z05_ScrollWorld_LimitLow:
    ; Don't let the scroll position go above $2100, the bottom of
    ; the status bar; nor below $2800, the top of NT 2.
    addq.b  #1,($0058,A4)
    even
ResetVScrollLo:
    moveq   #0,D0
    move.b  D0,($00E2,A4)
    even
IncSubmode:
    addq.b  #1,($0013,A4)
    rts

    even
ScrollWorldDownOrH:
    lsr.b  #1,D0   ; LSR A
    move.b  ($0098,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    bne.s  __far_z_05_0009
    jmp  ScrollWorldH
__far_z_05_0009:
    ; then scroll down.
    ;
    addq.b  #1,($00E9,A4)
    move.b  ($0084,A4),D0
    cmpi.b  #$3E,D0
    bcs  _anon_z05_11
    move.b  #$08,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$08
    eori    #$10,CCR  ; restore X = 6502 C
    move.b  D0,($0084,A4)
_anon_z05_11:
    move.b  ($00E2,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$20,D1
    addx.b  D1,D0   ; ADC #$20 (X flag = 6502 C)
    move.b  D0,($00E2,A4)
    bcc  _anon_z05_12
    addq.b  #1,($0058,A4)
_anon_z05_12:
    cmpi.b  #$C0,D0
    beq.s  __far_z_05_0010
    jmp  L14287_Exit
__far_z_05_0010:
    move.b  ($0058,A4),D0
    cmpi.b  #$23,D0
    beq.s  __far_z_05_0011
    jmp  L14287_Exit
__far_z_05_0011:
    ; VScroll address is $23C0, the bottom of NT 0. So, we need
    ; to roll to $2800, the top of NT 2.
    moveq   #40,D0
    move.b  D0,($0058,A4)
    jmp     ResetVScrollLo

    even
ScrollWorldH:
    moveq   #2,D0
    move.b  #$FE,D2
    moveq   #0,D3
    move.b  ($0010,A4),D3
    bne  _anon_z05_13
    lsl.b  #1,D0   ; ASL A
    move.b  #$FC,D2
_anon_z05_13:
    move.b  D0,($0000,A4)
    move.b  D2,($0001,A4)
    moveq   #2,D0
    move.b  ($0098,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    bne.s  __far_z_05_0012
    jmp  ScrollWorldRight
__far_z_05_0012:
    ; Scroll left.
    ;
    subq.b  #1,($00E8,A4)
    move.b  ($0070,A4),D0
    cmpi.b  #$F0,D0
    bcc  _anon_z05_14
    move.b  ($0000,A4),D1
    addx.b  D1,D0   ; ADC $00
    move.b  D0,($0070,A4)
_anon_z05_14:
    move.b  ($00FD,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  ($0000,A4),D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC $00
    eori    #$10,CCR  ; restore X = 6502 C
    move.b  D0,($00FD,A4)
    bne.s  __far_z_05_0013
    jmp  IncSubmode
__far_z_05_0013:
    move.b  ($0001,A4),D1
    cmp.b   D1,D0
    beq.s  __far_z_05_0014
    jmp  L14287_Exit
__far_z_05_0014:
    even
SwitchToNT1:
    ; When we begin scrolling left, CurHScroll = 0 and base
    ; nametable is 0. This shows the current room completely.
    ;
    ; The first time in ScrollWorld, the speed [00] will be
    ; subtracted from CurHScroll to show most of NT 0, and
    ; a little of NT 1 to its left. In other words, the
    ; scroll position now refers to a position in NT 1.
    ;
    ; [01] is this first position shown in NT 1. So, once
    ; CurHScroll matches it (in the first call to this routine),
    ; turn on this flag that makes NT 1 the base nametable.
    moveq   #1,D0
    move.b  D0,($005F,A4)
    even
L14287_Exit:
    rts

    even
ScrollWorldRight:
    lsr.b  #1,D0   ; LSR A
    move.b  ($0098,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    bne.s  __far_z_05_0015
    jmp  L14287_Exit
__far_z_05_0015:
    addq.b  #1,($00E8,A4)
    move.b  ($0070,A4),D0
    cmpi.b  #$01,D0
    bcs  _anon_z05_15
    move.b  ($0000,A4),D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC $00
    eori    #$10,CCR  ; restore X = 6502 C
    move.b  D0,($0070,A4)
_anon_z05_15:
    move.b  ($00FD,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($0000,A4),D1
    addx.b  D1,D0   ; ADC $00
    move.b  D0,($00FD,A4)
    beq.s  __far_z_05_0016
    jmp  L14287_Exit
__far_z_05_0016:
    ; Because CurHScroll is now 0 and base nametable is 0;
    ; we would be showing the new room at the end of the scroll
    ; but with old attributes.
    ;
    ; So, now use NT 1, until after we copy the attributes.
    jsr     SwitchToNT1
    jmp     IncSubmode

    even
InitMode7Submodes:
    move.b  ($0013,A4),D0
    jsr     _m68k_tablejump  ; M68K-native table dispatch (replaces JSR TableJump)
    even
InitMode7Submodes_JumpTable:
    dc.l    InitMode7_Sub0   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    InitMode7_Sub1   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    InitMode7_Sub2   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    InitMode7_Sub3And4_TransferPlayAreaAttrsToNT2   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    InitMode7_Sub3And4_TransferPlayAreaAttrsToNT2   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    InitMode7_Sub5   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    InitMode7_Sub6   ; jump table entry (32-bit for _m68k_tablejump)

    even
InitMode7_Sub1:
    jsr     DrawSpritesBetweenRooms
    jsr     Link_EndMoveAndAnimateBetweenRooms
    move.b  ($00EE,A4),D0
    move.b  D0,($0521,A4)
    ; If this doorway Link is entering from is not a true door,
    ; then LayOutDoors called from LayOutRoom will clear it.
    ;
    jsr     SetEnteringDoorwayAsCurOpenedDoors
    subq.b  #1,($00ED,A4)
    addq.b  #1,($0013,A4)
    jsr     CalculateNextRoom
    move.b  ($00EC,A4),D0
    ; If next room ID is invalid, then return because
    ; something went wrong calculating it.
    ; The mode was changed to load the OW.
    bmi  _L_z05_InitMode7_Sub1_Exit
    move.b  ($00EB,A4),D0
    move.b  D0,-(A5)  ; PHA
    moveq   #0,D3
    move.b  ($0098,A4),D3
    cmpi.b  #$08,D3
    ; If we're not going up, then temporarily set RoomId to next
    ; room; so we can draw next room in NT 2 below and
    ; subsequent submodes.
    ;
    ; Only in up direction do we draw the current room in NT 2.
    beq  _anon_z05_16
    move.b  ($00EC,A4),D0
    move.b  D0,($00EB,A4)
_anon_z05_16:
    jsr     FillPlayAreaAttrs
    moveq   #21,D0
    move.b  D0,($00E9,A4)
    moveq   #0,D3
    move.b  ($0098,A4),D3
    cmpi.b  #$08,D3
    beq  _anon_z05_17
    jsr     LayOutRoom
    even
_L_z05_InitMode7_Sub1_RestoreRoomId:
    move.b  (A5)+,D0  ; PLA
    move.b  D0,($00EB,A4)
    even
_L_z05_InitMode7_Sub1_Exit:
    rts

_anon_z05_17:
    jsr     LayOutDoorsPrev
    jmp     _L_z05_InitMode7_Sub1_RestoreRoomId

    even
LayOutDoorsPrev:
    move.b  ($0010,A4),D0
    beq  _anon_z05_18
    move.b  ($00EE,A4),D0
    move.b  D0,-(A5)  ; PHA
    move.b  ($0521,A4),D0
    move.b  D0,($00EE,A4)
    jsr     LayOutDoors
    move.b  (A5)+,D0  ; PLA
    move.b  D0,($00EE,A4)
_anon_z05_18:
    rts

    even
InitMode7_Sub0:
    ; If teleporting, then set the room ID to the one that will
    ; make it look like we scrolled to a dungeon entrance.
    move.b  ($0522,A4),D0
    beq  _anon_z05_19
    move.b  ($00EA,A4),D0
    move.b  D0,($00EB,A4)
_anon_z05_19:
    move.b  ($051A,A4),D0
    bne.s  __far_z_05_0017
    jmp  L1433A_IncSubmode
__far_z_05_0017:
    jmp     AnimatePond

    even
InitMode7_Sub2:
    ; This transfers a room's play area tiles to nametable 2.
    ;
    ; CurRow starts at the bottom ($15).
    jsr     CopyRowToTileBuf
    move.b  ($0302,A4),D0
    ; Change the target nametable from 0 to 2.
    ;
    ; Because there's only a play area and no status bar in
    ; nametable 2, you have to add 7 to the high byte instead of 8.
    ; So, the top of the play area in NT 0 is at $2100.
    ; But the top of the play area in NT 2 is at $2800.
    ;
    ; This assumes that you want to scroll vertically, where the
    ; two scroll areas must be contiguous vertically.
    andi.b #$0F,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$27,D1
    addx.b  D1,D0   ; ADC #$27 (X flag = 6502 C)
    move.b  D0,($0302,A4)
    move.b  ($0098,A4),D0
    cmpi.b  #$04,D0
    bcc  _anon_z05_20
    ; then you DO have to account for the status bar.
    ; So, add $100 (by incrementing high byte) to move
    ; everything down 64 pixels.
    ;
    ; Now the play areas will line up in NT 0 and NT 2 when
    ; we change mirroring to vertical at the end of this mode.
    addq.b  #1,($0302,A4)
_anon_z05_20:
    subq.b  #1,($00E9,A4)
    bpl  _anon_z05_21
    even
L1433A_IncSubmode:
    addq.b  #1,($0013,A4)
_anon_z05_21:
    rts

    even
InitMode7_Sub3And4_TransferPlayAreaAttrsToNT2:
    ; Transfer half of a room's play area attributes to nametable 2.
    ; The top half in submode 3, and the bottom half in submode 4.
    ;
    ;
    ; Test player's direction for up (8).
    moveq   #8,D0
    move.b  ($0098,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    bne  _L_z05_InitMode7_Sub3And4_TransferPlayAreaAttrsToNT2_Vertical
    lsr.b  #1,D0   ; LSR A
    move.b  ($0098,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    beq  _L_z05_InitMode7_Sub3And4_TransferPlayAreaAttrsToNT2_Horizontal
    even
_L_z05_InitMode7_Sub3And4_TransferPlayAreaAttrsToNT2_Vertical:
    ; Scrolling up or down.
    ;
    ;
    ; This will mean PPU address $2BC0.
    move.b  #$C0,D0
    even
_L_z05_InitMode7_Sub3And4_TransferPlayAreaAttrsToNT2_TransferHalfPlayAreaAttrs:
    moveq   #23,D3
    moveq   #0,D2
    move.b  ($0013,A4),D2
    cmpi.b  #$03,D2
    beq  _anon_z05_22
    jsr     GetPlayAreaAttrsBottomHalfInfo
_anon_z05_22:
    jmp     CueTransferPlayAreaAttrsHalfAndAdvanceSubmodeNT2

    even
_L_z05_InitMode7_Sub3And4_TransferPlayAreaAttrsToNT2_Horizontal:
    ; Scrolling left or right.
    ;
    ;
    ; This will mean PPU address $2BD0, 64 pixels down from
    ; the top of NT 2. See submode 2 for an explanation of
    ; offsets and mirroring for vertical scrolling.
    move.b  #$D0,D0
    bne  _L_z05_InitMode7_Sub3And4_TransferPlayAreaAttrsToNT2_TransferHalfPlayAreaAttrs
    even
InitMode7_Sub5:
    moveq   #0,D0
    move.b  D0,($051C,A4)
    move.b  ($0098,A4),D0
    cmpi.b  #$04,D0
    bcc  _L_z05_InitMode7_Sub5_Vertical
    ; then cue transfer of a row of blanks above the play area.
    ; This should lead to clean vertical scrolling without visual
    ; artifacts.
    ;
    ; TODO: But, maybe it doesn't work, because its address
    ; $28E0 is in NT 2, which will become a mirror of NT 0 below
    ; in this submode.
    moveq   #78,D3
    move.b  D3,($0014,A4)
    even
_L_z05_InitMode7_Sub5_Vertical:
    cmpi.b  #$08,D0
    bne  _L_z05_InitMode7_Sub5_CheckDark
    ; Scrolling up.
    ;
    ;
    ; Lay out the next room now, because we had to transfer
    ; the current one to NT 2 earlier. Up is the only direction
    ; that draws the current room to NT 2.
    move.b  ($00EB,A4),D0
    move.b  D0,-(A5)  ; PHA
    move.b  ($00EC,A4),D0
    move.b  D0,($00EB,A4)
    jsr     LayOutRoom
    move.b  (A5)+,D0  ; PLA
    move.b  D0,($00EB,A4)
    even
_L_z05_InitMode7_Sub5_CheckDark:
    ; Scrolling in any direction.
    ;
    moveq   #0,D3
    move.b  ($00EC,A4),D3
    jsr     IsDarkRoom_Bank5
    bne.s  __far_z_05_0018
    jmp  InitMode7_Finish
__far_z_05_0018:
    ; The next room is dark.
    ;
    moveq   #0,D3
    move.b  ($00EB,A4),D3
    jsr     IsDarkRoom_Bank5
    bne  _L_z05_InitMode7_Sub5_CheckIfLit
    even
_L_z05_InitMode7_Sub5_DarkenRoom:
    ; Going from room with light to a dark room.
    ;
    ;
    ; The next room will not be lit yet.
    moveq   #0,D0
    move.b  D0,($051F,A4)
    moveq   #64,D0
    move.b  D0,($051C,A4)
    addq.b  #1,($0013,A4)
    rts

    even
_L_z05_InitMode7_Sub5_CheckIfLit:
    move.b  ($051F,A4),D0
    bne  _L_z05_InitMode7_Sub5_DarkenRoom
    ; Not lit. Dark to dark. Nothing to do.
    ; Go finish initializing, and begin updating the mode.
    bne.s  __far_z_05_0019
    jmp  InitMode7_Finish
__far_z_05_0019:
    even
InitMode7_Sub6:
    jsr     AnimateWorldFading
    beq.s  __far_z_05_0020
    jmp  L143AD_Exit
__far_z_05_0020:
    even
InitMode7_Finish:
    ; Finish initializing this mode, and start updating it.
    ;
    ;
    ; Set current room to next room.
    move.b  ($00EC,A4),D0
    move.b  D0,($00EB,A4)
    jsr     WriteAndEnableSprite0
    jsr     BeginUpdateMode
    even
L143AD_Exit:
    rts

    even
Sprite0Descriptor:
    dc.b    $27, $61, $20, $58

    even
WriteAndEnableSprite0:
    moveq   #1,D0
    move.b  D0,($00E3,A4)
    moveq   #3,D3
_anon_z05_23:
    lea     (Sprite0Descriptor).l,A0
    move.b  (A0,D3.W),D0
    lea     ($0200,A4),A0
    move.b  D0,(A0,D3.W)
    subq.b  #1,D3
    bpl  _anon_z05_23
    rts

    even
SetEnteringDoorwayAsCurOpenedDoors:
    move.b  ($0098,A4),D0
    lsr.b  #1,D0   ; LSR A
    andi.b #$05,D0
    move.b  D0,($0000,A4)
    move.b  ($0098,A4),D0
    lsl.b  #1,D0   ; ASL A
    andi.b #$0A,D0
    move.b  ($0000,A4),D1
    or.b  D1,D0
    move.b  D0,($00EE,A4)
    rts

    even
RoomPaletteSelectorToNTAttr:
    dc.b    $00, $55, $AA, $FF

; Params:
; A: room ID
;
; Look up room attributes A for the room.
    even
FillPlayAreaAttrs:
    moveq   #0,D3
    move.b  D0,D3
    lea     (NES_SRAM+$087E).l,A0
    move.b  (A0,D3.W),D0
    andi.b #$03,D0
    moveq   #0,D2
    move.b  D0,D2
    lea     (RoomPaletteSelectorToNTAttr).l,A0
    move.b  (A0,D2.W),D0
    moveq   #47,D2
_anon_z05_24:
    lea     ($0530,A4),A0
    move.b  D0,(A0,D2.W)
    subq.b  #1,D2
    bpl  _anon_z05_24
    lea     (NES_SRAM+$08FE).l,A0
    move.b  (A0,D3.W),D0
    andi.b #$03,D0
    moveq   #0,D2
    move.b  D0,D2
    ; Fill the inner play area NT attributes (offset 9 to $26).
    ;
    moveq   #9,D3
    even
_L_z05_FillPlayAreaAttrs_LoopRow:
    move.b  D3,D0
    andi.b #$07,D0
    beq  _L_z05_FillPlayAreaAttrs_NextLoopRow
    cmpi.b  #$07,D0
    beq  _L_z05_FillPlayAreaAttrs_NextLoopRow
    cmpi.b  #$21,D3
    bcc  _L_z05_FillPlayAreaAttrs_CombineInnerOuter
    lea     (RoomPaletteSelectorToNTAttr).l,A0
    move.b  (A0,D2.W),D0
    lea     ($0530,A4),A0
    move.b  D0,(A0,D3.W)
    even
_L_z05_FillPlayAreaAttrs_NextLoopRow:
    addq.b  #1,D3
    cmpi.b  #$27,D3
    bcs  _L_z05_FillPlayAreaAttrs_LoopRow
    rts

    even
_L_z05_FillPlayAreaAttrs_CombineInnerOuter:
    ; Combine the NT attributes at current offset with the
    ; new ones we're filling; so that new (inner) attributes
    ; affect the top half of the row.
    lea     (RoomPaletteSelectorToNTAttr).l,A0
    move.b  (A0,D2.W),D0
    andi.b #$0F,D0
    move.b  D0,($0000,A4)
    lea     ($0530,A4),A0
    move.b  (A0,D3.W),D0
    andi.b #$F0,D0
    move.b  ($0000,A4),D1
    or.b  D1,D0
    lea     ($0530,A4),A0
    move.b  D0,(A0,D3.W)
    jmp     _L_z05_FillPlayAreaAttrs_NextLoopRow

    even
UpdateMode7SubmodeAndDrawLink:
    jsr     UpdateMode7ScrollSubmode
    jmp     Link_EndMoveAndAnimateBetweenRooms

    even
UpdateMode7ScrollSubmode:
    move.b  ($0013,A4),D0
    jsr     _m68k_tablejump  ; M68K-native table dispatch (replaces JSR TableJump)
    even
UpdateMode7ScrollSubmode_JumpTable:
    dc.l    UpdateMode7Scroll_Sub0   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    UpdateMode7Scroll_Sub1   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    UpdateMode7Scroll_Sub2   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    UpdateMode7Scroll_Sub3   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    UpdateMode7Scroll_Sub4   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    UpdateMode7Scroll_Sub4And5_TransferNTAttrs   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    UpdateMode7Scroll_Sub6   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    UpdateMode7Scroll_Sub7   ; jump table entry (32-bit for _m68k_tablejump)

    even
UpdateMode7Scroll_Sub0:
    moveq   #0,D0
    move.b  D0,($00E2,A4)
    move.b  D0,($00FD,A4)
    moveq   #8,D0
    move.b  ($0098,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    beq.s  __far_z_05_0021
    jmp  ScrollUp
__far_z_05_0021:
    lsr.b  #1,D0   ; LSR A
    move.b  ($0098,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    bne.s  __far_z_05_0022
    jmp  ScrollHorizontal
__far_z_05_0022:
    ; Scrolling down.
    ;
    ;
    ; Start scrolling from $2100, the top of play area in NT 0 (current room).
    moveq   #33,D0
    move.b  D0,($0058,A4)
    move.b  #$FF,D0
    move.b  D0,($00E9,A4)
    even
Inc2Submodes:
    addq.b  #1,($0013,A4)
    addq.b  #1,($0013,A4)
    rts

    even
ScrollHorizontal:
    ; Scrolling left or right.
    ;
    ; Keep in mind that columns will not be copied if CurColumn
    ; is not between 1 and $20.
    ;
    ; Set up a starting column number well past the beginning or
    ; end of the play area; so that we don't write to a part of
    ; the scroll region.
    ;
    ;
    ; $A0 in UW.
    move.b  #$A0,D3
    moveq   #0,D2
    move.b  ($0010,A4),D2
    bne  _anon_z05_25
    move.b  #$E0,D3
_anon_z05_25:
    lsr.b  #1,D0   ; LSR A
    move.b  ($0098,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    beq  _L_z05_ScrollHorizontal_SetColumn
    ; Scrolling left.
    ;
    ;
    ; $81 in UW.
    move.b  #$81,D3
    moveq   #0,D2
    move.b  ($0010,A4),D2
    bne  _L_z05_ScrollHorizontal_SetColumn
    moveq   #65,D3
    even
_L_z05_ScrollHorizontal_SetColumn:
    move.b  D3,($00E8,A4)
    jmp     Inc2Submodes

    even
ScrollUp:
    ; Scrolling up.
    ;
    ;
    ; Start scrolling from $2800, the top of play area in NT 2 (current room).
    moveq   #40,D0
    move.b  D0,($0058,A4)
    moveq   #22,D0
    move.b  D0,($00E9,A4)
    move.b  ($00EB,A4),D0
    jsr     FillPlayAreaAttrs
    even
UpdateMode7Scroll_Sub1:
    jsr     ChooseAttrSourceAndDestForSubmode
    jmp     CueTransferPlayAreaAttrsHalfAndAdvanceSubmodeNT0

    even
ChooseAttrSourceAndDestForSubmode:
    ; Results:
    ; A: low PPU address
    ; Y: end offset in PlayAreaAttrs to copy from
    ;
    ;
    ; Low byte $D0 mean destination PPU address of $23D0, $27D0, $2BD0, or $2FD0.
    move.b  #$D0,D0
    moveq   #23,D3
    moveq   #0,D2
    move.b  ($0013,A4),D2
    beq  _anon_z05_26
; Params:
; A: low PPU address
;
; Returns:
; A: low PPU address + $18
; Y: end offset of second half of play area NT attributes
;
;
; This is the offset of the end of the second half of play area NT attributes.
    even
GetPlayAreaAttrsBottomHalfInfo:
    moveq   #47,D3
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$18,D1
    addx.b  D1,D0   ; ADC #$18 (X flag = 6502 C)
_anon_z05_26:
    rts

    even
UpdateMode7Scroll_Sub2:
    ; Calculates a VScrollingStartFrame value that enables
    ; immediate vertical scrolling in the next frame and submode.
    ;
    addq.b  #1,($0013,A4)
    move.b  ($0015,A4),D0
    ; Add 1, so that the frame value calculated in the next frame
    ; will match the VScrollingStartFrame value we calculate here.
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$01,D1
    addx.b  D1,D0   ; ADC #$01 (X flag = 6502 C)
    ; Calculate VScrollingStartFrame the same way as the frame
    ; value in the next submode.
    andi.b #$03,D0
    moveq   #0,D3
    move.b  ($0010,A4),D3
    bne  _anon_z05_27
    andi.b #$01,D0
_anon_z05_27:
    move.b  D0,($00E6,A4)
    rts

    even
UpdateMode7Scroll_Sub3:
    jsr     ScrollWorld
    jsr     CopyColumnOrRowToTileBuf
    move.b  ($0013,A4),D0
    cmpi.b  #$03,D0
    beq  _anon_z05_28
    move.b  #$FF,D3
    move.b  D3,($00E9,A4)
    move.b  D3,($00ED,A4)
    addq.b  #1,D3
    move.b  D3,($00E8,A4)
_anon_z05_28:
    rts

    even
UpdateMode7Scroll_Sub6:
    move.b  ($0010,A4),D0
    bne.s  __far_z_05_0023
    jmp  UpdateMode7Scroll_Sub7
__far_z_05_0023:
    moveq   #0,D3
    move.b  ($00EB,A4),D3
    jsr     IsDarkRoom_Bank5
    bne.s  __far_z_05_0024
    jmp  UpdateMode7Scroll_Sub7
__far_z_05_0024:
    ; Set CurRow = 0 (was $FF) to signal to mode 4 that
    ; it might need to brighten the new room, because we
    ; scrolled from a dark one.
    ;
    ; This isn't a concern, if you enter a room by any other mode.
    moveq   #0,D0
    move.b  D0,($00E9,A4)
    addq.b  #1,($0013,A4)
    rts

    even
UpdateMode7Scroll_Sub7:
    moveq   #1,D0
    move.b  D0,($0013,A4)
    lsr.b  #1,D0   ; LSR A
    move.b  D0,($0011,A4)
    move.b  D0,($010C,A4)
    move.b  D0,($00E7,A4)
    move.b  D0,($00E3,A4)
    moveq   #4,D0
    move.b  D0,($0012,A4)
    rts

    even
UpdateMode7Scroll_Sub4:
    ; Transfer new room's attributes to NT 0.
    ;
    moveq   #8,D0
    move.b  ($0098,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    bne.s  __far_z_05_0025
    jmp  UpdateMode7Scroll_Sub4And5_TransferNTAttrs
__far_z_05_0025:
    jmp     Inc2Submodes

    even
UpdateMode7Scroll_Sub4And5_TransferNTAttrs:
    move.b  #$D0,D0
    moveq   #23,D3
    moveq   #0,D2
    move.b  ($0013,A4),D2
    cmpi.b  #$04,D2
    bne.s  __far_z_05_0026
    jmp  CueTransferPlayAreaAttrsHalfAndAdvanceSubmodeNT0
__far_z_05_0026:
    ; Transfer bottom half.
    ;
    ;
    ; Save low byte of PPU address of top of play area attributes.
    move.b  D0,-(A5)  ; PHA
    move.b  ($0098,A4),D0
    cmpi.b  #$04,D0
    bcc  _anon_z05_29
    moveq   #0,D0
    move.b  D0,($005F,A4)
_anon_z05_29:
    move.b  (A5)+,D0  ; PLA
    jsr     GetPlayAreaAttrsBottomHalfInfo
; Params:
; A: low PPU address
; Y: end offset in PlayAreaAttrs to copy from
;
;
; High byte of destination PPU address for play area attributes.
    even
CueTransferPlayAreaAttrsHalfAndAdvanceSubmodeNT0:
    moveq   #35,D2
    jmp     CueTransferPlayAreaAttrsHalfAndAdvanceSubmode

    even
CopyColumnOrRowToTileBuf:
    ; Copies a row if CurRow is valid. Otherwise, tries to copy a column.
    ;
    ; If CurRow = PrevRow, does nothing. After a row is copied,
    ; PrevRow is assigned CurRow.
    ;
    ;
    ; If CurRow is valid, then copy row.
    move.b  ($00E9,A4),D0
    cmpi.b  #$16,D0
    bcc  _L_z05_CopyColumnOrRowToTileBuf_CheckColumn
    move.b  ($00ED,A4),D1
    cmp.b   D1,D0
    beq  _L_z05_CopyColumnOrRowToTileBuf_Exit
    move.b  D0,($00ED,A4)
    jmp     CopyRowToTileBuf

    even
_L_z05_CopyColumnOrRowToTileBuf_CheckColumn:
    move.b  ($00E8,A4),D0
    beq  _L_z05_CopyColumnOrRowToTileBuf_Exit
    cmpi.b  #$21,D0
    bcc  _L_z05_CopyColumnOrRowToTileBuf_Exit
    jmp     CopyColumnToTileBuf

    even
_L_z05_CopyColumnOrRowToTileBuf_Exit:
    rts

    even
WaitAndScrollToSplitBottom:
    jsr     _ppu_read_2  ; PPU $2002 read → D0
    andi.b #$40,D0
    bne.s  __far_z_05_0027
    jmp  WaitAndScrollToSplitBottom
__far_z_05_0027:
    jsr     _ppu_read_2  ; PPU $2002 read → D0
    ; Wait cycles.
    ; TODO: Why do these differ?
    ; (cycle at 8535 - cycle at 852b) = 1005  (see CPU status in debugger)
    ; (multiply instruction timing appropriately) = 1010
    moveq   #3,D3
_anon_z05_30:
    moveq   #48,D2
_anon_z05_31:
    subq.b  #1,D2
    bpl  _anon_z05_31
    subq.b  #1,D3
    bpl  _anon_z05_30
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    nop
    move.b  ($0012,A4),D0
    cmpi.b  #$08,D0
    bcc  _anon_z05_35
    move.b  ($0013,A4),D0
    beq  _L_z05_WaitAndScrollToSplitBottom_Exit
    move.b  ($0098,A4),D0
    cmpi.b  #$04,D0
    bcs  _anon_z05_33
    ; Scrolling vertically, will set PPUADDR instead of PPUSCROLL.
    ; Wait about 666 cycles.
    moveq   #94,D3
_anon_z05_32:
    nop
    subq.b  #1,D3
    bpl  _anon_z05_32
    nop
    nop
    nop
    nop
    nop
    jsr     _ppu_read_2  ; PPU $2002 read → D0
    ; Set PPUADDR mid-frame to 
    ; achieve split-frame scrolling.
    move.b  ($0058,A4),D0
    moveq   #0,D3
    move.b  ($00E2,A4),D3
    jsr     _ppu_write_6  ; PPU $2006 write, D0=val
    move.l  D0,-(SP)       ; save A (6502 STX/STY never modifies A)
    move.b  D3,D0  ; D3 → D0 for I/O write
    jsr     _ppu_write_6  ; PPU $2006 write, D0=val
    move.l  (SP)+,D0       ; restore A
    jsr     _ppu_read_7  ; PPU $2007 read → D0
    jsr     _ppu_read_7  ; PPU $2007 read → D0
    rts

_anon_z05_33:
    moveq   #94,D3
_anon_z05_34:
    nop
    subq.b  #1,D3
    bpl  _anon_z05_34
    nop
    nop
    nop
    move.b  ($00FF,A4),D0
    andi.b #$FE,D0
    move.b  ($005F,A4),D1
    or.b  D1,D0
    move.b  D0,($00FF,A4)
    jsr     _ppu_write_0  ; PPU $2000 write, D0=val
    move.b  ($00FD,A4),D0
    jsr     _ppu_write_5  ; PPU $2005 write, D0=val
    moveq   #0,D0
    jsr     _ppu_write_5  ; PPU $2005 write, D0=val
    even
_L_z05_WaitAndScrollToSplitBottom_Exit:
    rts

_anon_z05_35:
    cmpi.b  #$11,D0
    bcc  _anon_z05_36
