    even
InitMode4:
    moveq   #0,D2
    move.b  ($0013,A4),D2
    bne.s  __far_z_05_0028
    jmp  InitMode_EnterRoom
__far_z_05_0028:
    subq.b  #1,D2
    bne  _L_z05_InitMode4_CheckSub2
    ; Submode 1.
    ; Copies the whole play area to NT 0, one row each frame.
    ;
    ; TODO:
    ; If mode 7 scrolls to a dark room, then it sets
    ; CurRow to zero. Otherwise it would be $FF.
    ; A positive value triggers this submode 1 to transfer
    ; the whole play area.
    ;
    ; But why? As far as I can tell, the NT 0 is already in
    ; a good state reflecting the new room. The only thing
    ; needed is possibly to brighten the room by way of
    ; changing the palette.
    ;
    ; So why does mode 7 trigger this?
    ; Is there another mode that truly needs this behavior?
    ;
    move.b  ($00E9,A4),D0
    bmi  _anon_z05_40
    jsr     CopyNextRowToTransferBuf
    bcc  _L_z05_InitMode4_Exit
_anon_z05_40:
    addq.b  #1,($0013,A4)
    even
_L_z05_InitMode4_Exit:
    rts

    even
_L_z05_InitMode4_CheckSub2:
    subq.b  #1,D2
    beq.s  __far_z_05_0029
    jmp  InitMode4_Sub3
__far_z_05_0029:
    ; Submode 2.
    ;
    moveq   #0,D3
    move.b  ($00EB,A4),D3
    jsr     IsDarkRoom_Bank5
    beq.s  __far_z_05_0030
    jmp  InitMode4_GoToSub0
__far_z_05_0030:
    ; This is a light room.
    ; See if we have to brighten it after leaving a dark room.
    ;
    move.b  ($0098,A4),D0
    jsr     CalcNextRoomByDir
    ; Subtract RoomId from next room ID that was calculated
    ; to get room ID offset in that direction.
    ori     #$11,CCR  ; SEC: set C+X
    move.b  ($00EB,A4),D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC RoomId
    eori    #$10,CCR  ; restore X = 6502 C
    jsr     Negate
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($00EB,A4),D1
    addx.b  D1,D0   ; ADC RoomId
    moveq   #0,D3
    move.b  D0,D3
    jsr     IsDarkRoom_Bank5
    bne.s  __far_z_05_0031
    jmp  InitMode4_GoToSub0
__far_z_05_0031:
    ; The previous room was dark.
    ;
    move.b  ($051F,A4),D0
    beq.s  __far_z_05_0032
    jmp  InitMode4_GoToSub0
__far_z_05_0032:
    move.b  #$C0,D0
; Params:
; A: start index of cycle
;
    even
SetFadeCycleAndAdvanceSubmode:
    move.b  D0,($051C,A4)
    addq.b  #1,($0013,A4)
_anon_z05_41:
    rts

    even
InitMode4_Sub3:
    ; Submode 3.
    ;
    jsr     AnimateWorldFading
    bne  _anon_z05_41
    even
InitMode4_GoToSub0:
    moveq   #0,D0
    move.b  D0,($0013,A4)
    move.b  D0,($051F,A4)
    rts

; Description:
; Clears intraroom data.
; Set up Link to walk into a room.
; Decodes and lays out objects.
; Switches from initializing the game mode to updating it.
;
; This is called for modes 4, 9, $B, $C.
;
    even
InitMode_EnterRoom:
    jsr     DrawSpritesBetweenRooms
    jsr     ResetPlayerState
    ; Reset [0300] to [051F].
    ;
    moveq   #5,D0
    moveq   #31,D3
    jsr     ClearRam0300UpTo
    ; Reset door trigger info.
    ;
    moveq   #0,D0
    move.b  D0,($0054,A4)
    move.b  D0,($0055,A4)
    ; Store level block attribute byte F for convenience.
    ;
    moveq   #0,D3
    move.b  ($00EB,A4),D3
    lea     (NES_SRAM+$0AFE).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($04CD,A4)
    jsr     ResetInvObjState
    ; There's more than one way to enter a room.
    ;
    ; 1: Out of a cave, dungeon, or cellar
    ;     a. Walking exit
    ;     b. Next to stairs
    ; 2: Room to room
    ;
    ; Determine which one we need.
    ;
    move.b  ($005A,A4),D0
    beq  _L_z05_InitMode_EnterRoom_Method2
    move.b  ($0010,A4),D0
    bne  _anon_z05_42
    ; Enter method 1.
    ;
    ; Set up Link's exit from underground.
    ;
    moveq   #0,D3
    move.b  ($00EB,A4),D3
    lea     (NES_SRAM+$087E).l,A0
    move.b  (A0,D3.W),D0
    andi.b #$F0,D0
    move.b  D0,($0070,A4)
    lea     (NES_SRAM+$0AFE).l,A0
    move.b  (A0,D3.W),D0
    andi.b #$07,D0
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    ; Add the first Y where Link can come out of underground.
    ; $4D is $50 (the second square row) - 3 (Link's offset above the row).
    move.b  #$4D,D1
    addx.b  D1,D0   ; ADC #$4D (X flag = 6502 C)
    move.b  D0,($0084,A4)
    ; If the player didn't step on a cave entrance to go underground,
    ; then he used the stairs. So, skip starting the exit effect (method 1-b).
    ;
    moveq   #0,D3
    move.b  ($0065,A4),D3
    cmpi.b  #$24,D3
    bne  _anon_z05_42
    ; Enter method 1-a.
    ;
    ; Store the Y coordinate that we determined as the Target Y.
    ;
    move.b  D0,($0412,A4)
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$10,D1
    addx.b  D1,D0   ; ADC #$10 (X flag = 6502 C)
    move.b  D0,($0084,A4)
    moveq   #8,D0
    move.b  D0,($0603,A4)
_anon_z05_42:
    ; This part is the same no matter if the player went
    ; underground by stairs or a cave entrance.
    ;
    moveq   #4,D0
    move.b  D0,($0098,A4)
    moveq   #0,D0
    move.b  D0,($0053,A4)
    jmp     _L_z05_InitMode_EnterRoom_PlaceObjects

    even
_L_z05_InitMode_EnterRoom_Method2:
    ; Enter method 2.
    ; Room to room.
    ;
    ; Get the direction that the player is entering from.
    ;
    move.b  ($0098,A4),D0
    move.b  D0,($0053,A4)
    jsr     GetOppositeDir
    ; If the player is entering from a door that was opened, then
    ; set the "close" door command.
    ;
    move.b  ($00EE,A4),D1
    and.b  D1,D0
    move.b  D0,($0055,A4)
    beq  _anon_z05_43
    moveq   #2,D0
    move.b  D0,($0054,A4)
_anon_z05_43:
    ; If in OW, go reset Link's relative position, and work on objects.
    ;
    move.b  ($0010,A4),D0
    beq  _L_z05_InitMode_EnterRoom_PlaceObjects
    ; If facing right, then set Link's X to 0 at the left edge.
    ; If direction is left, then set Link's X to $F0 at the right edge.
    ;
    moveq   #0,D3
    move.b  ($0098,A4),D0
    andi.b #$03,D0
    beq  _L_z05_InitMode_EnterRoom_ChooseWalkDistance
    andi.b #$01,D0
    bne  _anon_z05_44
    move.b  #$F0,D3
_anon_z05_44:
    move.b  D3,($0070,A4)
    even
_L_z05_InitMode_EnterRoom_ChooseWalkDistance:
    ; Choose a distance to walk depending on the door you
    ; come out of.
    ;
    ; We'll get a 0 or 1 depending on the direction of the door.
    ;
    ; If the attribute of the door is "open", "key", or "key 2";
    ; then you have shorter distance to cover. So use the
    ; previous value as is to use indexes 0 and 1.
    ;
    ; Otherwise, add 2 to use indexes 2 and 3 to walk farther
    ; to get out of the way of the wall or door.
    ;
    jsr     GetPassedDoorType
    andi.b #$07,D0
    beq  _anon_z05_45
    cmpi.b  #$05,D0
    beq  _anon_z05_45
    cmpi.b  #$06,D0
    beq  _anon_z05_45
    addq.b  #1,D3
    addq.b  #1,D3
_anon_z05_45:
    lea     (EnteringRoomRelativePositions).l,A0
    move.b  (A0,D3.W),D0
    even
_L_z05_InitMode_EnterRoom_PlaceObjects:
    move.b  D0,($0394,A4)
    jsr     SetupObjRoomBounds
    ; Set current object slot variable to $B, to be ready for the
    ; first frame of mode 5. So, that it begins updating objects
    ; at slot $B.
    ;
    moveq   #11,D2
    move.b  D2,($0340,A4)
_anon_z05_46:
    ; Reset common state of objects $B to 1.
    ;
    lea     ($0492,A4),A0
    subq.b  #1,(A0,D2.W)
    jsr     ResetShoveInfo
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  D0,($3D,A4,D2.W)
    lea     ($03D0,A4),A0
    addq.b  #1,(A0,D2.W)
    lea     ($0405,A4),A0
    addq.b  #1,(A0,D2.W)
    moveq   #32,D0
    lea     ($03BC,A4),A0
    move.b  D0,(A0,D2.W)
    subq.b  #1,D2
    bne  _anon_z05_46
    ; Put the monster list ID in [02].
    ;
    moveq   #0,D3
    move.b  ($00EB,A4),D3
    lea     (NES_SRAM+$097E).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,-(A5)  ; PHA
    andi.b #$3F,D0
    move.b  D0,($0002,A4)
    lea     (NES_SRAM+$09FE).l,A0
    move.b  (A0,D3.W),D0
    lsl.b  #1,D0   ; ASL A
    bcc  _anon_z05_47
    move.b  ($0002,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$40,D1
    addx.b  D1,D0   ; ADC #$40 (X flag = 6502 C)
    move.b  D0,($0002,A4)
_anon_z05_47:
    move.b  (A5)+,D0  ; PLA
    ; Get index of monster count from high 2 bits of attribute byte C.
    ;
    andi.b #$C0,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    roxl.b  #1,D0   ; ROL A
    roxl.b  #1,D0   ; ROL A
    roxl.b  #1,D0   ; ROL A
    moveq   #0,D3
    move.b  D0,D3
    ; Get the object count from level info.
    ;
    lea     (NES_SRAM+$0BA2).l,A0
    move.b  (A0,D3.W),D0
    ; But make the count 1, if  the object list ID >= $32 and < $62.
    ; This includes bosses and other non-recurring objects.
    ;
    moveq   #0,D3
    move.b  ($0002,A4),D3
    cmpi.b  #$62,D3
    bcc  _anon_z05_48
    cmpi.b  #$32,D3
    bcs  _anon_z05_48
    moveq   #1,D0
_anon_z05_48:
    move.b  D0,($0003,A4)
    ; Use the room history to modify the number of objects to make.
    ;
    move.b  ($0010,A4),D0
    bne  _anon_z05_49
    jsr     ModifyObjCountByHistoryOW
    jmp     _L_z05_InitMode_EnterRoom_StoreObjCount

_anon_z05_49:
    jsr     ModifyObjCountByHistoryUW
    ; If in mode 9 (most caves), then
    ; reset object count and object list ID.
    ;
    move.b  ($0012,A4),D0
    cmpi.b  #$09,D0
    bne  _L_z05_InitMode_EnterRoom_StoreObjCount
    moveq   #0,D0
    move.b  D0,($0002,A4)
    move.b  D0,($0003,A4)
    even
_L_z05_InitMode_EnterRoom_StoreObjCount:
    move.b  ($0003,A4),D0
    move.b  D0,($034E,A4)
    ; If object count = 0 or object list ID = 0, then
    ; skip instantiating objects.
    ;
    beq  _L_z05_InitMode_EnterRoom_SkipObjects
    move.b  ($0002,A4),D0
    beq  _L_z05_InitMode_EnterRoom_SkipObjects
    ; TODO: If object list ID (or call it object template ID?) >= $62,
    ; then it refers to a list. Go handle it.
    ;
    cmpi.b  #$62,D0
    bcc  _L_z05_InitMode_EnterRoom_PlaceList
    ; TODO: Object list ID (or call it object template ID) refers to a
    ; repeated object.
    ;
    ; Set the object type at each element from 1 to Object Count
    ; to object list ID (or call it object template ID).
    ;
    moveq   #0,D2
_anon_z05_50:
    move.b  ($0002,A4),D0
    lea     ($0350,A4),A0
    move.b  D0,(A0,D2.W)
    addq.b  #1,D2
    subq.b  #1,($0003,A4)
    bne  _anon_z05_50
    jmp     _L_z05_InitMode_EnterRoom_StoreObjTemplate

    even
_L_z05_InitMode_EnterRoom_PlaceList:
    ; TODO: Object list ID (or call it object template ID) refers to a
    ; list of object types.
    ;
    ; Get the index of the list itself by subtracting $62.
    ;
    move.b  ($0002,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$62,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$62
    eori    #$10,CCR  ; restore X = 6502 C
    ; Put the address of the list in [04:05].
    ;
    lsl.b  #1,D0   ; ASL A
    moveq   #0,D3
    move.b  D0,D3
    lea     (ObjListAddrs).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0004,A4)
    addq.b  #1,D3
    lea     (ObjListAddrs).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0005,A4)
    ; Copy elements from the list to ObjType up to object count [03].
    ;
    moveq   #0,D3
_anon_z05_51:
    move.b  ($04,A4),D1   ; ptr lo
    move.b  ($05,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    lea     ($0350,A4),A0
    move.b  D0,(A0,D3.W)
    addq.b  #1,D3
    move.b  ($0003,A4),D1
    cmp.b   D1,D3
    bne  _anon_z05_51
    even
_L_z05_InitMode_EnterRoom_StoreObjTemplate:
