    move.b  ($00EB,A4),D3
    lea     (NES_SRAM+$08FE).l,A0
    move.b  (A0,D3.W),D0
    andi.b #$FC,D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$40,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$40
    eori    #$10,CCR  ; restore X = 6502 C
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    ; cave dweller object type = $6A + (cave index)
    ;
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$6A,D1
    addx.b  D1,D0   ; ADC #$6A (X flag = 6502 C)
    move.b  D0,($0350,A4)
