    move.b  ($0084,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC ObjY,X
    eori    #$10,CCR  ; restore X = 6502 C
    jsr     Abs
    cmpi.b  #$22,D0
    bcc.s  __far_z_05_0034
    jmp  ReturnUnsafeToSpawn
__far_z_05_0034:
_anon_z05_62:
    andi    #$EE,CCR  ; CLC: clear C+X
    rts

    even
ReturnUnsafeToSpawn:
