CheckSecretTriggerBlockDoor:
    ; If the block has not been pushed completely, then return C=0.
    ;
    move.b  ($04CF,A4),D0
    bne.s  __far_z_05_0046
    jmp  ReturnFalse
__far_z_05_0046:
    ; Else go trigger shutters to open, and return C=1.
