    move.b  #$D0,D0
    move.b  D0,($70,A4,D2.W)
    moveq   #96,D0
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    moveq   #112,D0
    jsr     ChangeTileObjTiles
    ; Return C=1.
