; Three sets of border coordinates:
; - outer OW
; - outer UW
; - inner
;
; Within each set, the coordinates are arranged:
; down, up, right, left
;
    even
BorderBounds:
    dc.b    $D6, $45, $E9, $07, $C6, $55, $D9, $17
    dc.b    $BE, $54, $D1, $1F

    even
Link_FilterInput:
    ; [00] holds the opposite of Link's facing direction.
    ;
    move.b  ($0098,A4),D0
    jsr     GetOppositeDir
    move.b  D0,($0000,A4)
    ; Call GetOppositeDir again to use this mapping:
    ; In Dir: 1 2 4 8
    ;         -------
    ; Index:  2 3 0 1
    ;
    jsr     GetOppositeDir
    ; Get the appropriate coordinate for the direction:
    ; X for horizontal
    ; Y for vertical
    ;
    move.b  ($0070,A4),D0
    cmpi.b  #$02,D3
    bcc  _anon_z05_74
    move.b  ($0084,A4),D0
_anon_z05_74:
    move.b  D0,($0002,A4)
    ; Mask A button and directions if inner border is crossed.
    ;
    move.b  D3,D0
    move.b  D0,-(A5)  ; PHA
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$08,D1
    addx.b  D1,D0   ; ADC #$08 (X flag = 6502 C)
    moveq   #0,D3
    move.b  D0,D3
    move.b  #$80,D0
    jsr     MaskInputInBorder
    move.b  (A5)+,D0  ; PLA
    moveq   #0,D3
    move.b  D0,D3
    ; If inner boundary was not crossed, then we'll check the outer
    ; boundary using player's direction and reverse direction index.
    ;
    move.b  ($0001,A4),D0
    cmpi.b  #$FF,D0
    bne  _anon_z05_75
    move.b  ($0098,A4),D0
    move.b  D0,($0000,A4)
    jsr     GetOppositeDir
_anon_z05_75:
    ; If in UW, use the second set of bounds by adding 4
    ; to reverse direction index.
    ;
    ; Else in OW, and use first set that begins at offset 0.
    ;
    move.b  ($0010,A4),D0
    beq  _anon_z05_76
    move.b  D3,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$04,D1
    addx.b  D1,D0   ; ADC #$04 (X flag = 6502 C)
    moveq   #0,D3
    move.b  D0,D3
_anon_z05_76:
    ; We won't mask buttons (A) this time. Only directions now.
    ;
    moveq   #0,D0
; Params:
; A: mask of buttons to block
; Y: offset into BorderBounds
; [00]: direction
; [02]: coordinate
;
; Returns:
; [01]: button mask that was used
;       (set to $FF if boundary not crossed)
;
    even
MaskInputInBorder:
    move.b  D0,($0001,A4)
    ; If direction is positive (right or down), then go handle it separately.
    ;
    move.b  ($0000,A4),D0
    andi.b #$0A,D0
    beq  _L_z05_MaskInputInBorder_PositiveDir
    ; The direction is negative (left or up).
    ;
    ; If the coordinate does not cross (<) the boundary, then
    ; go set mask $FF, so that no button is excluded.
    ;
    move.b  ($0002,A4),D0
    lea     (BorderBounds).l,A0
    move.b  (A0,D3.W),D1
    cmp.b   D1,D0
    bcs  _L_z05_MaskInputInBorder_ExcludeNone
    even
_L_z05_MaskInputInBorder_MaskButtons:
    ; The boundary was crossed. Mask buttons.
    ;
    move.b  ($00F8,A4),D0
    move.b  ($0001,A4),D1
    and.b  D1,D0
    move.b  D0,($00F8,A4)
    ; If in OW or button mask <> 0, return.
    ;
    move.b  ($0010,A4),D0
    beq  _L_z05_MaskInputInBorder_Exit
    move.b  ($0001,A4),D0
    bne  _L_z05_MaskInputInBorder_Exit
    ; Mask off input directions perpendicular to player's facing.
    ;
    moveq   #12,D3
    move.b  ($0098,A4),D0
    andi.b #$0C,D0
    bne  _anon_z05_77
    moveq   #3,D3
_anon_z05_77:
    move.b  D3,D0
    move.b  ($03F8,A4),D1
    and.b  D1,D0
    move.b  D0,($03F8,A4)
    even
_L_z05_MaskInputInBorder_Exit:
    rts

    even
_L_z05_MaskInputInBorder_PositiveDir:
    ; The direction is positive.
    ;
    ; If the coordinate crosses (<) the boundary, then
    ; go mask buttons.
    ;
    ;
    ; Get coordinate in [02].
    move.b  ($0002,A4),D0
    lea     (BorderBounds).l,A0
    move.b  (A0,D3.W),D1
    cmp.b   D1,D0
    bcs  _L_z05_MaskInputInBorder_MaskButtons
    even
_L_z05_MaskInputInBorder_ExcludeNone:
    ; The coordinate is not crossed; then set mask $FF,
    ; so that no button is excluded.
    ;
    move.b  #$FF,D0
    move.b  D0,($0001,A4)
    even
L14DFF_Exit:
    rts

