CheckSubroom:
    move.b  ($0012,A4),D0
    cmpi.b  #$09,D0
    bne  _L_z05_CheckSubroom_InCave
    ; In a cellar.
    ;
    ; If Link's Y >= $40 or input direction <> up, return.
    ;
    move.b  ($0084,A4),D0
    cmpi.b  #$40,D0
    bcs.s  __far_z_05_0070
    jmp  L14EC6_Exit
__far_z_05_0070:
    move.b  ($03F8,A4),D0
    andi.b #$08,D0
    bne.s  __far_z_05_0071
    jmp  L14EC6_Exit
__far_z_05_0071:
    ; Look for this room's ID in the 6-element cellar room array.
    ;
    moveq   #6,D3
    move.b  ($00EB,A4),D0
    move.b  D0,-(A5)  ; PHA
_anon_z05_81:
    subq.b  #1,D3
    lea     (NES_SRAM+$0BB2).l,A0
    move.b  (A0,D3.W),D1
    cmp.b   D1,D0
    bne  _anon_z05_81
    ; Determine the destination room ID, and go there.
    ;
    ; If Link's X < $80 look in level block attributes A, else B.
    ;
    ; Note that in cellars, level block attributes A and B indicate
    ; the destination room ID only.
    ;
    moveq   #0,D3
    move.b  D0,D3
    move.b  ($0070,A4),D0
    cmpi.b  #$80,D0
    bcc  _L_z05_CheckSubroom_GetRightSideRoom
    lea     (NES_SRAM+$087E).l,A0
    move.b  (A0,D3.W),D0
    jmp     _anon_z05_82

    even
_L_z05_CheckSubroom_GetRightSideRoom:
    lea     (NES_SRAM+$08FE).l,A0
    move.b  (A0,D3.W),D0
_anon_z05_82:
    jsr     GoToModeAFromCellar
    ; Set Link's position in the destination room.
    ;
    move.b  (A5)+,D0  ; PLA
    moveq   #0,D3
    move.b  D0,D3
    lea     (NES_SRAM+$097E).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,-(A5)  ; PHA
    andi.b #$F0,D0
    move.b  D0,($0070,A4)
    move.b  (A5)+,D0  ; PLA
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    ori.b #$0D,D0
    move.b  D0,($0084,A4)
    rts

    even
_L_z05_CheckSubroom_InCave:
    ; In a cave.
    ;
    ; Check whether a person is blocking the upper half of the room.
    ;
    move.b  D0,-(A5)  ; PHA
    jsr     CheckPersonBlocking
    move.b  (A5)+,D0  ; PLA
    ; If mode is not $C (shortcuts), go check the screen edge.
    ;
    cmpi.b  #$0C,D0
    beq.s  __far_z_05_0072
    jmp  CheckCaveEdge
__far_z_05_0072:
    ; In a shortcut cave (mode $C).
    ;
    ; If grid offset <> 0, return.
    ;
    move.b  ($0394,A4),D0
    beq.s  __far_z_05_0073
    jmp  L14F72_Exit
__far_z_05_0073:
    ; If Link's Y <> $9D, go check the screen edge.
    ;
    move.b  ($0084,A4),D0
    cmpi.b  #$9D,D0
    beq.s  __far_z_05_0074
    jmp  CheckCaveEdge
__far_z_05_0074:
    ; See if Link is on one of the 3 shortcut stairs.
    ; X = $50: 1
    ; X = $80: 2
    ; X = $B0: 3
    ;
    ; If he's not on any, then return.
    ;
    moveq   #1,D3
    move.b  ($0070,A4),D0
    cmpi.b  #$50,D0
    beq  _anon_z05_83
    addq.b  #1,D3
    cmpi.b  #$80,D0
    beq  _anon_z05_83
    addq.b  #1,D3
    cmpi.b  #$B0,D0
    beq.s  __far_z_05_0075
    jmp  L14F72_Exit
__far_z_05_0075:
_anon_z05_83:
    ; Look for the current room in the cellar/shortcut room array.
    ;
    move.b  D3,($0000,A4)
    move.b  #$FF,D3
    move.b  ($00EB,A4),D0
_anon_z05_84:
    addq.b  #1,D3
    lea     (NES_SRAM+$0BB2).l,A0
    move.b  (A0,D3.W),D1
    cmp.b   D1,D0
    bne  _anon_z05_84
    ; Add the value of the shortcut chosen to whatever index
    ; the current room has in the array.
    ;
    ; This yields the index of one of the three shortcut rooms
    ; after the current one.
    ;
    move.b  D3,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($0000,A4),D1
    addx.b  D1,D0   ; ADC $00
    ; Wrap around if needed. Go to that room by way of mode $A.
    ;
    andi.b #$03,D0
    moveq   #0,D3
    move.b  D0,D3
    lea     (NES_SRAM+$0BB2).l,A0
    move.b  (A0,D3.W),D0
; Params:
; A: destination room ID
;
    even
GoToModeAFromCellar:
    move.b  D0,($00EB,A4)
    jsr     MarkRoomVisited
    even
GoToModeAFromCave:
    moveq   #10,D0
    move.b  D0,($0012,A4)
    even
EndPrepareMode:
    moveq   #0,D0
    move.b  D0,($0013,A4)
    move.b  D0,($0011,A4)
    move.b  D0,($000F,A4)
    move.b  D0,($00AC,A4)
    move.b  D0,($00C0,A4)
    move.b  D0,($00D3,A4)
    move.b  D0,($04F0,A4)
    even
L14F72_Exit:
