ModifyObjCountByHistoryOW:
    ;Look for the room in the history.
    ;
    moveq   #5,D3
    move.b  ($00EB,A4),D0
_anon_z05_90:
    lea     ($0621,A4),A0
    move.b  (A0,D3.W),D1
    cmp.b   D1,D0
    beq  _anon_z05_91
    subq.b  #1,D3
    bpl  _anon_z05_90
    ; It wasn't found. Check the kill count in the room flags.
    ;
    jsr     GetRoomFlags
    andi.b #$07,D0
    cmpi.b  #$07,D0
    bne  _anon_z05_91
    ; The room is not in history, and all foes were defeated.
    ; So, reset the kill count in room flags.
    ;
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    andi.b #$F8,D0
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4
    ext.l   D4
    add.l   #NES_RAM,D4
    movea.l D4,A0
    move.b  D0,(A0,D3.W)     ; STA ($nn),Y
    even
_L_z05_ModifyObjCountByHistoryOW_Exit:
