    move.b  ($0003,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  ($0004,A4),D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC $04
    eori    #$10,CCR  ; restore X = 6502 C
    bpl  _anon_z05_92
    even
_L_z05_ModifyObjCountByHistoryOW_ResetObjList:
    moveq   #0,D0
    move.b  D0,($0002,A4)
_anon_z05_92:
    move.b  D0,($0003,A4)
    rts

