Link_ModifyDirInDoorway:
    ; In a doorway (UW), you can only move in the direction
    ; that you entered it or the opposite.
    ;
    ;
    ; If not in a doorway nor moving, then return.
    ;
    move.b  ($0053,A4),D0
    beq  _L_z05_Link_ModifyDirInDoorway_Exit
    moveq   #0,D3
    move.b  ($03F8,A4),D3
    beq  _L_z05_Link_ModifyDirInDoorway_Exit
    ; If the facing direction is part of the input direction, then
    ; keep moving in the facing direction.
    ;
    move.b  ($0098,A4),D0
    move.b  ($03F8,A4),D1
    and.b  D1,D0
    bne  _anon_z05_94
    ; If the opposite of the facing direction is part of the input direction, then
    ; face the opposite direction.
    ;
    move.b  ($0098,A4),D0
    jsr     GetOppositeDir
    move.b  ($03F8,A4),D1
    and.b  D1,D0
    ; If neither direction matched input direction, then
    ; change input direction to facing direction.
    ;
    bne  _anon_z05_94
    move.b  ($0098,A4),D0
_anon_z05_94:
    move.b  D0,($03F8,A4)
    even
_L_z05_Link_ModifyDirInDoorway_Exit:
    rts

; Unknown block
    dc.b    $A9, $F8, $8D, $40, $02, $8D, $44, $02
    dc.b    $60

; To be considered within a doorway, one condition is that
; Link's perpendicular coordinate ([00]) has to match the doorway's
; (X=$78 for verticals, Y=$8D for horizontals).
;
; See GetPlayerCoordsForDirection.
;
    even
DoorwayRequiredCoord:
    dc.b    $78, $78, $8D, $8D

; Player coordinate must be >= these bounds.
; Using these bounds; the player will be considered within the
; bounds of a doorway, if strictly inside or 1 pixel outside.
;
    even
DoorwayBoundsMinOver:
    dc.b    $3D, $BD, $00, $CF

; Player coordinate must be < these bounds.
; Using these bounds; the player will be considered within the
; bounds of a doorway, if strictly inside or 1 pixel outside.
;
    even
DoorwayBoundsMaxOver:
    dc.b    $5E, $DE, $21, $F1

; Player coordinate must be >= these bounds.
; Using these bounds; the player will be considered within the
; bounds of a doorway, if strictly inside except for 1 or 2 pixels
; at the edge.
;
    even
DoorwayBoundsMinUnder:
    dc.b    $3D, $BF, $00, $D2

; Player coordinate must be < these bounds.
; Using these bounds; the player will be considered within the
; bounds of a doorway, if strictly inside except for 1 or 2 pixels
; at the edge.
;
    even
DoorwayBoundsMaxUnder:
    dc.b    $5C, $DE, $1F, $F1

; Params:
; [0F]: moving direction
;
; Returns:
; [0E]: reverse index of doorway direction found, or $FF if blocked
; [0F]: untouched, or changed from 0 to a moving direction
;
; When not at or in a doorway, this function leaves
; [0F] moving direction as is.
;
; When blocked by a door, [0E] will be set to $FF. But [0F]
; will be left as is, assuming that it had been reset before this
; routine by BoundByRoom.
;
; Otherwise, [0F] will be changed from 0 to the door's direction.
;
;
; If already in a doorway, go handle it separately.
;
    even
CheckDoorway:
    move.b  ($0053,A4),D0
    bne  _L_z05_CheckDoorway_InDoorway
    even
_L_z05_CheckDoorway_SearchOverflowBounds:
    ; Not in a doorway. Look for a doorway that Link might be in.
    ;
    ; To match a doorway:
    ; 1. Link's [00] coordinate has to match the doorway's
    ;    (X=$78 for verticals, Y=$8D for horizontals)
    ; 2. Link's [01] coordinate has to >=  min bound, and < max bound
    ;
    ; The "overflow" bounds are used that consider 1 pixel outside
    ; a doorway to be part of it.
    ;
    move.b  ($0098,A4),D0
    jsr     GetPlayerCoordsForDirection
    moveq   #3,D3
    even
_L_z05_CheckDoorway_LoopOverflowBounds:
    move.b  ($0000,A4),D0
    lea     (DoorwayRequiredCoord).l,A0
    move.b  (A0,D3.W),D1
    cmp.b   D1,D0
    bne  _anon_z05_95
    move.b  ($0001,A4),D0
    lea     (DoorwayBoundsMinOver).l,A0
    move.b  (A0,D3.W),D1
    cmp.b   D1,D0
    bcs  _anon_z05_95
    lea     (DoorwayBoundsMaxOver).l,A0
    move.b  (A0,D3.W),D1
    cmp.b   D1,D0
    bcs  _L_z05_CheckDoorway_TestDoorwayDoor
_anon_z05_95:
    subq.b  #1,D3
    bpl  _L_z05_CheckDoorway_LoopOverflowBounds
    even
_L_z05_CheckDoorway_NotInDoorway:
    ; Not in any doorway. Reset DoorwayDir.
    ; Leave [0F] moving direction as is.
    ;
    moveq   #0,D0
    move.b  D0,($0053,A4)
    rts

    even
_L_z05_CheckDoorway_InDoorway:
    ; In a doorway. DoorwayDir is in A.
    ;
    move.b  D0,-(A5)  ; PHA
    jsr     GetPlayerCoordsForDirection
    move.b  (A5)+,D0  ; PLA
    jsr     GetOppositeDir
    move.b  ($0001,A4),D0
    ; If the player is within the bounds of the doorway for DoorwayDir
    ; (for example the left door way, if DoorwayDir = left;
    ; instead of right doorway while DoorwayDir = left),
    ; and player is facing in DoorwayDir, then go repeat the
    ; original search used to enter the doorway.
    ;
    lea     (DoorwayBoundsMinOver).l,A0
    move.b  (A0,D3.W),D1
    cmp.b   D1,D0
    bcs  _L_z05_CheckDoorway_SearchUnderflowDoorway
    lea     (DoorwayBoundsMaxOver).l,A0
    move.b  (A0,D3.W),D1
    cmp.b   D1,D0
    bcc  _L_z05_CheckDoorway_SearchUnderflowDoorway
    move.b  ($0053,A4),D0
    move.b  ($0098,A4),D1
    cmp.b   D1,D0
    beq  _L_z05_CheckDoorway_SearchOverflowBounds
    even
_L_z05_CheckDoorway_SearchUnderflowDoorway:
    ; The player might be in the original doorway facing backwards,
    ; outside it, or in the other doorway along the axis.
    ;
    ; Look for a doorway that Link might be in.
    ; The difference between this search and the one above
    ; is that we check the "underflow" bounds that are shorter than
    ; the full doorway length.
    ;
    moveq   #3,D3
    even
_L_z05_CheckDoorway_LoopUnderflowDoorway:
    move.b  ($0000,A4),D0
    lea     (DoorwayRequiredCoord).l,A0
    move.b  (A0,D3.W),D1
    cmp.b   D1,D0
    bne  _anon_z05_96
    move.b  ($0001,A4),D0
    lea     (DoorwayBoundsMinUnder).l,A0
    move.b  (A0,D3.W),D1
    cmp.b   D1,D0
    bcs  _anon_z05_96
    lea     (DoorwayBoundsMaxUnder).l,A0
    move.b  (A0,D3.W),D1
    cmp.b   D1,D0
    bcs  _L_z05_CheckDoorway_TestDoorwayDoor
_anon_z05_96:
    subq.b  #1,D3
    bpl  _L_z05_CheckDoorway_LoopUnderflowDoorway
    bmi  _L_z05_CheckDoorway_NotInDoorway
    even
_L_z05_CheckDoorway_TestDoorwayDoor:
    ;
    ;
    ; [0E] holds reverse index of doorway direction found.
    ;
    move.b  D3,($000E,A4)
    ; Store input direction in [02] and [0C].
    ;
    move.b  ($03F8,A4),D0
    andi.b #$0F,D0
    move.b  D0,($0002,A4)
    move.b  D0,($000C,A4)
    ; If input direction is not the doorway direction found, return.
    ;
    lea     (ReverseDirections).l,A0
    move.b  (A0,D3.W),D1
    cmp.b   D1,D0
    bne  _L_z05_CheckDoorway_Exit
    ; Touch the door in the direction we found.
    ;
    jsr     FindDoorAttrByDoorBit
    move.b  D0,($000D,A4)
    jsr     TouchDoor
    ; If blocked, then return and leave DoorwayDir as it was.
    ;
    moveq   #0,D3
    move.b  ($000E,A4),D3
    bmi  _L_z05_CheckDoorway_Exit
    ; Set variables to doorway direction found.
    ;
    lea     (ReverseDirections).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0098,A4)
    move.b  D0,($000F,A4)
    move.b  D0,($0053,A4)
    ; Movement was not blocked at a doorway.
    ; If we're at a false wall or bombable, then go pass thru it
    ; and leave the room.
    ;
    move.b  ($000D,A4),D0
    andi.b #$07,D0
    cmpi.b  #$02,D0
    beq  _anon_z05_97
    cmpi.b  #$03,D0
    beq  _anon_z05_97
    cmpi.b  #$04,D0
    beq  _anon_z05_97
    even
_L_z05_CheckDoorway_Exit:
    rts

_anon_z05_97:
    jmp     GoToNextModeFromPlay

; Params:
; A: direction
;
; Returns:
; [00]: coordinate on perpendicular axis
; [01]: coordinate on direction's axis
;
; [00]: Y if facing left or right, else X
; [01]: X if facing left or right, else Y
;
    even
GetPlayerCoordsForDirection:
    moveq   #0,D2
    move.b  ($0070,A4),D2
    moveq   #0,D3
    move.b  ($0084,A4),D3
    andi.b #$03,D0
    beq  _anon_z05_98
    moveq   #0,D3
    move.b  ($0070,A4),D3
    moveq   #0,D2
    move.b  ($0084,A4),D2
_anon_z05_98:
    move.b  D2,($0000,A4)
    move.b  D3,($0001,A4)
    rts

; Params:
; [0C]: door direction
; [0E]: reverse index of direction
;
; Returns:
; [0E]: untouched, or $FF if blocked
;
    even
TouchDoor:
    andi.b #$07,D0
    jsr     _m68k_tablejump  ; M68K-native table dispatch (replaces JSR TableJump)
    even
TouchDoor_JumpTable:
    dc.l    TouchDoorOpen   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    TouchDoorWall   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    TouchDoorFalse   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    TouchDoorFalse   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    TouchDoorBombable   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    TouchDoorKey   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    TouchDoorKey   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    TouchDoorShutter   ; jump table entry (32-bit for _m68k_tablejump)

    even
TouchDoorWall:
    move.b  #$FF,D3
    move.b  D3,($000E,A4)
    even
TouchDoorOpen:
    rts

    even
TouchDoorFalse:
    ; At first, Link's timer = 0. So set it to $18 frames, and block movement.
    ; Subsequently, block movement until timer = 1.
    ;
    move.b  ($0028,A4),D0
    beq  _L_z05_TouchDoorFalse_SetTimer
    cmpi.b  #$01,D0
    bne  _L_z05_TouchDoorFalse_BlockMovement
    rts

    even
_L_z05_TouchDoorFalse_SetTimer:
    moveq   #24,D0
    move.b  D0,($0028,A4)
    even
_L_z05_TouchDoorFalse_BlockMovement:
    jmp     TouchDoorWall

    even
TouchDoorBombable:
    ; Block movement, if this door's direction is not in the open door mask.
    ;
    move.b  ($000C,A4),D0
    move.b  ($00EE,A4),D1
    and.b  D1,D0
    bne.s  __far_z_05_0077
    jmp  TouchDoorWall
__far_z_05_0077:
    rts

    even
TouchDoorShutter:
    ; If a door is triggered or this door wasn't already opened,
    ; then block movement.
    ;
    move.b  ($0054,A4),D0
    beq.s  __far_z_05_0078
    jmp  TouchDoorWall
__far_z_05_0078:
    move.b  ($000C,A4),D0
    move.b  ($00EE,A4),D1
    and.b  D1,D0
    bne.s  __far_z_05_0079
    jmp  TouchDoorWall
__far_z_05_0079:
    ; TODO: ?
    ;
    move.b  ($0519,A4),D1
    and.b  D1,D0
    beq  _anon_z05_99
    beq.s  __far_z_05_0080
    jmp  BlockUntilTime
__far_z_05_0080:
_anon_z05_99:
    move.b  ($0519,A4),D0
    move.b  ($000C,A4),D1
    or.b  D1,D0
    move.b  D0,($0519,A4)
    rts

    even
TouchDoorKey:
    ; If this door was already opened, return.
    ;
    move.b  ($000C,A4),D0
    move.b  ($00EE,A4),D1
    and.b  D1,D0
    beq.s  __far_z_05_0081
    jmp  L15292_Exit
__far_z_05_0081:
    ; If a door is triggered, go block movement while Link's timer <> 0.
    ;
    move.b  ($0054,A4),D0
    beq.s  __far_z_05_0082
    jmp  BlockUntilTime
__far_z_05_0082:
    ; If we don't have the magic key nor any normal keys, 
    ; go block movement.
    ;
    move.b  ($0664,A4),D0
    bne  _L_z05_TouchDoorKey_TriggerDoor
    move.b  ($066E,A4),D0
    bne.s  __far_z_05_0083
    jmp  BlockAtWall
__far_z_05_0083:
    ; If we don't have the magic key, decrease the key count.
    ;
    subq.b  #1,($066E,A4)
    even
_L_z05_TouchDoorKey_TriggerDoor:
    ; Trigger this door to open.
    ;
    move.b  ($000C,A4),D0
    jsr     TriggerOpenDoor
    ; Set player's timer to block for $20 frames.
    ;
    moveq   #32,D0
    move.b  D0,($0028,A4)
    even
BlockAtWall:
    jmp     TouchDoorWall

    even
BlockUntilTime:
    ; Block movement while Link's timer <> 0.
    ;
    move.b  ($0028,A4),D0
    beq.s  __far_z_05_0084
    jmp  BlockAtWall
__far_z_05_0084:
    even
L15292_Exit:
    rts

    even
ModifyObjCountByHistoryUW:
    ; Look for the room in the history.
    ;
    moveq   #5,D3
    move.b  ($00EB,A4),D0
_anon_z05_100:
    lea     ($0621,A4),A0
    move.b  (A0,D3.W),D1
    cmp.b   D1,D0
    beq  _L_z05_ModifyObjCountByHistoryUW_CalcObjCount
    subq.b  #1,D3
    bpl  _anon_z05_100
    ; It wasn't found. Check the kill count in the room flags.
    ;
    jsr     GetRoomFlags
    andi.b #$C0,D0
    cmpi.b  #$C0,D0
    bne  _L_z05_ModifyObjCountByHistoryUW_CalcObjCount
    ; The room is not in history, and all foes were defeated.
    ; Does the object list ID indicate a non-recurring object?
    ;
    move.b  ($0002,A4),D0
    cmpi.b  #$32,D0
    bcs  _anon_z05_101
    cmpi.b  #$3A,D0
    beq  _anon_z05_101
    cmpi.b  #$3B,D0
    beq  _anon_z05_101
    cmpi.b  #$49,D0
    bcs  _L_z05_ModifyObjCountByHistoryUW_ResetObjCount
_anon_z05_101:
    ; The object list ID is for recurring objects.
    ; So, reset the kill count in room flags and level block.
    ;
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    andi.b #$3F,D0
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4
    ext.l   D4
    add.l   #NES_RAM,D4
    movea.l D4,A0
    move.b  D0,(A0,D3.W)     ; STA ($nn),Y
    moveq   #0,D0
    lea     ($0560,A4),A0
    move.b  D0,(A0,D3.W)
    rts

    even
_L_z05_ModifyObjCountByHistoryUW_CalcObjCount:
    ; Subtract the level block's kill count from the object count.
    ;
    moveq   #0,D3
    move.b  ($00EB,A4),D3
    move.b  ($0003,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
    lea     ($0560,A4),A0
    move.b  (A0,D3.W),D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC LevelKillCounts,Y
    eori    #$10,CCR  ; restore X = 6502 C
    bpl  _anon_z05_102
    even
_L_z05_ModifyObjCountByHistoryUW_ResetObjCount:
    moveq   #0,D0
    move.b  D0,($0002,A4)
_anon_z05_102:
    move.b  D0,($0003,A4)
    rts

    even
SaveKillCountUW:
    jsr     GetRoomFlags
    andi.b #$3F,D0
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4
    ext.l   D4
    add.l   #NES_RAM,D4
    movea.l D4,A0
    move.b  D0,(A0,D3.W)     ; STA ($nn),Y
    move.b  ($034E,A4),D0
    beq  _L_z05_SaveKillCountUW_StoreMax
    move.b  ($034F,A4),D0
    beq  _anon_z05_103
    ; If the object template type is ...
    ; >= $32 and
    ; <> $3A and
    ; <> $3B and
    ; <  $49,
    ; then it refers to a non-recurring foe that shouldn't be made
    ; again. So, go store the max kill count for the room.
    ; 
    moveq   #0,D3
    move.b  ($035F,A4),D3
    cmpi.b  #$32,D3
    bcs  _anon_z05_103
    cmpi.b  #$3A,D3
    beq  _anon_z05_103
    cmpi.b  #$3B,D3
    beq  _anon_z05_103
    cmpi.b  #$49,D3
    bcs  _L_z05_SaveKillCountUW_StoreMax
_anon_z05_103:
    ; Compare RoomKillCount and RoomFoeCount.
    ;
    move.b  ($034E,A4),D1
    cmp.b   D1,D0
    bcc  _L_z05_SaveKillCountUW_StoreMax
    ; RoomKillCount < _RoomObjCount.
    ; Add RoomKillCount to level kill count for this room.
    ;
    moveq   #0,D3
    move.b  ($00EB,A4),D3
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     ($0560,A4),A0
    move.b  (A0,D3.W),D1
    addx.b  D1,D0   ; ADC LevelKillCounts,Y
    lea     ($0560,A4),A0
    move.b  D0,(A0,D3.W)
    cmpi.b  #$03,D0
    bcs  _anon_z05_104
    moveq   #2,D0
_anon_z05_104:
    andi    #$EE,CCR  ; CLC: clear C+X
    roxr.b  #1,D0   ; ROR A
    roxr.b  #1,D0   ; ROR A
    roxr.b  #1,D0   ; ROR A
    jmp     _L_z05_SaveKillCountUW_CombineWithFlags

    even
_L_z05_SaveKillCountUW_StoreMax:
    moveq   #0,D3
    move.b  ($00EB,A4),D3
    moveq   #15,D0
    lea     ($0560,A4),A0
    move.b  D0,(A0,D3.W)
    move.b  #$C0,D0
    even
_L_z05_SaveKillCountUW_CombineWithFlags:
    move.b  ($00,A4),D1
    move.b  ($01,A4),D4
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4
    ext.l   D4
    add.l   #NES_RAM,D4
    movea.l D4,A0
    move.b  (A0,D3.W),D1
    or.b  D1,D0
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4
    ext.l   D4
    add.l   #NES_RAM,D4
    movea.l D4,A0
    move.b  D0,(A0,D3.W)     ; STA ($nn),Y
    rts

    even
