; Params:
; [02]: bitmask for target door.
;
; Returns:
; A: door attribute for desired direction in current room.
; [01]: same as [02] if found; $10 otherwise
; [03]: reverse direction index
;
; Door bits:
; 1: E
; 2: W
; 4: S
; 8: N
;
;
; Start with single-bit mask 1.
    even
FindDoorAttrByDoorBit:
    moveq   #1,D0
    move.b  D0,($0001,A4)
    moveq   #3,D0
    move.b  D0,($0003,A4)
    even
_L_z05_FindDoorAttrByDoorBit_LoopDoorBit:
    moveq   #0,D3
    move.b  ($00EB,A4),D3
    lea     (NES_SRAM+$087E).l,A0
    move.b  (A0,D3.W),D0
    moveq   #0,D3
    move.b  ($0003,A4),D3
    cmpi.b  #$02,D3
    bcs  _anon_z05_106
    moveq   #0,D3
    move.b  ($00EB,A4),D3
    lea     (NES_SRAM+$08FE).l,A0
    move.b  (A0,D3.W),D0
_anon_z05_106:
    move.b  D0,($0000,A4)
    move.b  ($0003,A4),D0
    andi.b #$01,D0
    bne  _anon_z05_107
    move.b  ($0000,A4),D1
    lsr.b  #1,D1   ; LSR $00
    move.b  D1,($0000,A4)
    move.b  ($0000,A4),D1
    lsr.b  #1,D1   ; LSR $00
    move.b  D1,($0000,A4)
    move.b  ($0000,A4),D1
    lsr.b  #1,D1   ; LSR $00
    move.b  D1,($0000,A4)
_anon_z05_107:
    move.b  ($0000,A4),D1
    lsr.b  #1,D1   ; LSR $00
    move.b  D1,($0000,A4)
    move.b  ($0000,A4),D1
    lsr.b  #1,D1   ; LSR $00
    move.b  D1,($0000,A4)
    ; Now [$00] holds isolated door attribute.
    ;
    ;
    ; Test mask passed in [$02] with current single-bit mask in [$01].
    move.b  ($0002,A4),D0
    move.b  ($0001,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    bne  _anon_z05_108
    move.b  ($0001,A4),D1
    lsl.b  #1,D1   ; ASL $01
    move.b  D1,($0001,A4)
    subq.b  #1,($0003,A4)
    bpl  _L_z05_FindDoorAttrByDoorBit_LoopDoorBit
    moveq   #8,D0
    rts

_anon_z05_108:
    move.b  ($0000,A4),D0
    andi.b #$07,D0
    rts

    even
ReachedTopWallBottom:
    ; Read a zero tile. Reached the bottom of a top wall.
    ;
    ; Set up A and X to move top and bottom offsets to the next column.
    ;
    moveq   #19,D0
    ; TODO: I think that any value >= 4 would work here;
    ; so that we keep processing the wall tile list.
    move.b  D0,($0006,A4)
    moveq   #25,D2
    beq.s  __far_z_05_0085
    jmp  MoveWallPtrs
__far_z_05_0085:
    even
DecBottomOffset:
    ; Subtract A=1 from bottom offset.
    ;
    jsr     Sub1FromInt16At4
    jmp     NextLoopWallTile

    even
FillWalls:
    ; Load the address of WallTileList.
    ;
    moveq   #0,D0
    move.b  D0,($0000,A4)
    moveq   #0,D0
    move.b  D0,($0001,A4)
    ; Load the address of second tile in second row of PlayAreaTiles.
    ; This is where we'll start loading tiles for the room.
    moveq   #71,D0
    move.b  D0,($0002,A4)
    moveq   #101,D0
    move.b  D0,($0003,A4)
    ; Load the address of second last tile in second row of PlayAreaTiles.
    ; This is where we'll stop loading tiles for the room.
    moveq   #90,D0
    move.b  D0,($0004,A4)
    moveq   #101,D0
    move.b  D0,($0005,A4)
    moveq   #10,D0
    move.b  D0,($0006,A4)
    moveq   #0,D3
    even
LoopWallTile:
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    bne.s  __far_z_05_0086
    jmp  ReachedTopWallBottom
__far_z_05_0086:
    move.b  ($02,A4),D1   ; ptr lo
    move.b  ($03,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4
    ext.l   D4
    add.l   #NES_RAM,D4
    movea.l D4,A0
    move.b  D0,(A0,D3.W)     ; STA ($nn),Y
    move.b  ($04,A4),D1   ; ptr lo
    move.b  ($05,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4
    ext.l   D4
    add.l   #NES_RAM,D4
    movea.l D4,A0
    move.b  D0,(A0,D3.W)     ; STA ($nn),Y
    ; If the tile isn't the vertical line $DE nor anything >= $E2,
    ; then set the bottom tile to the next one, which is flipped
    ; vertically. For example, $E0 => $E1.
    cmpi.b  #$DE,D0
    beq  _anon_z05_109
    cmpi.b  #$E2,D0
    bcc  _anon_z05_109
    move.b  #$01,D1
    addx.b  D1,D0   ; ADC #$01 (X flag = 6502 C)
    move.b  ($04,A4),D1   ; ptr lo
    move.b  ($05,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4
    ext.l   D4
    add.l   #NES_RAM,D4
    movea.l D4,A0
    move.b  D0,(A0,D3.W)     ; STA ($nn),Y
_anon_z05_109:
    moveq   #1,D0
    moveq   #1,D2
    subq.b  #1,($0006,A4)
    beq.s  __far_z_05_0087
    jmp  MoveWallPtrs
__far_z_05_0087:
    moveq   #10,D0
    move.b  D0,($0006,A4)
    moveq   #13,D0
    ; $1F means add this amount to bottom offset to move
    ; it to bottom of next column.
    moveq   #31,D2
    even
MoveWallPtrs:
    jsr     AddToInt16At2
    move.b  D2,D0
    subq.b  #1,D2
    bne.s  __far_z_05_0088
    jmp  DecBottomOffset
__far_z_05_0088:
    ; Else add the original X value to bottom offset,
    ; intending to move it to the bottom of the next column.
    jsr     AddToInt16At4
    even
NextLoopWallTile:
    jsr     Add1ToInt16At0
    cmpi.b  #$00,D0
    beq.s  __far_z_05_0089
    jmp  LoopWallTile
__far_z_05_0089:
    ; Copy rotated 180 degrees, accounting for appropriate
    ; horizontal or vertical flipping of tiles.
    ;
    ; The source is in the top left.
    moveq   #48,D0
    move.b  D0,($0002,A4)
    moveq   #101,D0
    move.b  D0,($0003,A4)
    move.b  #$EF,D0
    move.b  D0,($0004,A4)
    moveq   #103,D0
    move.b  D0,($0005,A4)
    even
_L_z05_NextLoopWallTile_LoopRotate:
    move.b  ($02,A4),D1   ; ptr lo
    move.b  ($03,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    move.b  ($04,A4),D1   ; ptr lo
    move.b  ($05,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4
    ext.l   D4
    add.l   #NES_RAM,D4
    movea.l D4,A0
    move.b  D0,(A0,D3.W)     ; STA ($nn),Y
    cmpi.b  #$DD,D0
    beq  _L_z05_NextLoopWallTile_SwapWithVertical
    cmpi.b  #$E0,D0
    bcc  _L_z05_NextLoopWallTile_NextLoopRotate
    cmpi.b  #$DC,D0
    bcc  _anon_z05_110
    move.b  #$01,D1
    addx.b  D1,D0   ; ADC #$01 (X flag = 6502 C)
    move.b  ($04,A4),D1   ; ptr lo
    move.b  ($05,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4
    ext.l   D4
    add.l   #NES_RAM,D4
    movea.l D4,A0
    move.b  D0,(A0,D3.W)     ; STA ($nn),Y
_anon_z05_110:
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$01,D1
    addx.b  D1,D0   ; ADC #$01 (X flag = 6502 C)
    even
_L_z05_NextLoopWallTile_SetRotatedTile:
    move.b  ($04,A4),D1   ; ptr lo
    move.b  ($05,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4
    ext.l   D4
    add.l   #NES_RAM,D4
    movea.l D4,A0
    move.b  D0,(A0,D3.W)     ; STA ($nn),Y
    even
_L_z05_NextLoopWallTile_NextLoopRotate:
    jsr     Sub1FromInt16At4
    jsr     Add1ToInt16At2
    cmpi.b  #$90,D0
    bne  _L_z05_NextLoopWallTile_LoopRotate
    move.b  ($0003,A4),D0
    cmpi.b  #$66,D0
    bne  _L_z05_NextLoopWallTile_LoopRotate
    rts

    even
_L_z05_NextLoopWallTile_SwapWithVertical:
    move.b  #$DC,D0
    bne  _L_z05_NextLoopWallTile_SetRotatedTile
    even
DoorBits:
    dc.b    $01, $02, $04, $08

    even
DoorFaceTilesAddrsLo:
    dc.b    $EE   ; <DoorFaceTilesE (NES=$9FEE)
    dc.b    $2A   ; <DoorFaceTilesW (NES=$A02A)
    dc.b    $66   ; <DoorFaceTilesS (NES=$A066)
    dc.b    $A2   ; <DoorFaceTilesN (NES=$A0A2)

    even
DoorFaceTilesAddrsHi:
    dc.b    $9F   ; >DoorFaceTilesE (NES=$9FEE)
    dc.b    $A0   ; >DoorFaceTilesW (NES=$A02A)
    dc.b    $A0   ; >DoorFaceTilesS (NES=$A066)
    dc.b    $A0   ; >DoorFaceTilesN (NES=$A0A2)

    even
PlayAreaDoorFaceAddrsLo:
    dc.b    ($67A1)&$FF
    dc.b    ($654F)&$FF
    dc.b    ($6676)&$FF
    dc.b    ($6665)&$FF

    even
PlayAreaDoorFaceAddrsHi:
    dc.b    ($67A1>>8)&$FF
    dc.b    ($654F>>8)&$FF
    dc.b    ($6676>>8)&$FF
    dc.b    ($6665>>8)&$FF

    even
NextDoorTileOffsets:
    dc.b    $14, $01, $01

    even
DirIndexToDoorSecondHalfOffsets:
