LayOutDoors:
    ; Copies the right door face for the direction, type, and state
    ; of the door to the play area tile map.
    ;
    ; Also, clears door bits from CurOpenedDoors of doorways
    ; that are not true doors.
    ;
    moveq   #3,D2
    even
L_LayOutDoors_LoopDoors:
    ; For each door, indexed by X, from 3 (N) to 0:
    ;
    moveq   #1,D0
    ; For each half of a door, indexed by [06], from 1 to 0:
    ;
    ; [06] indicates whether we're handling the first half of
    ; the door: Left half for N/S, Top half for E/W.
    ;
    move.b  D0,($0006,A4)
    even
L_LayOutDoors_LoopHalves:
    move.b  D2,D0
    move.b  D0,-(A5)  ; PHA
    move.b  D0,($000B,A4)
    lea     (DoorBits).l,A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0002,A4)
    jsr     FindDoorAttrByDoorBit
    ; Begin looking for the door face for the door attribute.
    ; In general, use the door type as the provisional face;
    ; except turn 4 into 8.
    ;
    cmpi.b  #$05,D0
    bcc  _L_z05_L_LayOutDoors_LoopHalves_DoneClosedPF
    cmpi.b  #$04,D0
    bne  _L_z05_L_LayOutDoors_LoopHalves_ClearFromOpenedMask
    moveq   #8,D0
    bne  _L_z05_L_LayOutDoors_LoopHalves_DoneClosedPF
    even
_L_z05_L_LayOutDoors_LoopHalves_SetPF9:
    ; We jump here if the door type is bombable and was opened.
    ; Change the provisional door face to value 9, which
    ; will become the "hole in the wall".
    ;
    moveq   #9,D0
    bne  _L_z05_L_LayOutDoors_LoopHalves_DoneOpenPF
    even
_L_z05_L_LayOutDoors_LoopHalves_ClearFromOpenedMask:
    ; Door attribute < 4 (open or any wall), clear door bit from
    ; the mask of opened doors, because this is not a true door.
    ;
    move.b  D0,-(A5)  ; PHA
    move.b  ($0002,A4),D0
    eori.b #$FF,D0
    move.b  ($00EE,A4),D1
    and.b  D1,D0
    move.b  D0,($00EE,A4)
    move.b  (A5)+,D0  ; PLA
    ; Furthermore, if door type = 0, then use 4 as the provisional face.
    ;
    cmpi.b  #$01,D0
    bcc  _L_z05_L_LayOutDoors_LoopHalves_DoneClosedPF
    moveq   #4,D0
    even
_L_z05_L_LayOutDoors_LoopHalves_DoneClosedPF:
    ; The door attribute (DA) has been mapped to a
    ; provisional door face value (PF) in %A as follows:
    ;
    ; DA PF Meaning
    ; -------------
    ; 0  4  open
    ; 1  1  wall
    ; 2  2  false wall
    ; 3  3  false wall 2
    ; 4  8  bombable
    ; 5  5  key
    ; 6  6  key 2
    ; 7  7  shutter
    ;
    ; Also at this point, the door bit in CurOpenedDoors
    ; has been cleared, if the type was "open" or any wall.
    ;
    ;
    ; Save the provisional face.
    move.b  D0,-(A5)  ; PHA
    ; If the current direction points to a door that has been opened,
    ; then see if we need to set door flags.
    ;
    move.b  ($00EE,A4),D0
    move.b  ($0002,A4),D1
    and.b  D1,D0
    moveq   #0,D2
    move.b  D0,D2
    move.b  (A5)+,D0  ; PLA
    move.b  ($0002,A4),D1
    cmp.b   D1,D2
    bne  _L_z05_L_LayOutDoors_LoopHalves_DoneOpenPF
    ; The current direction points to a door that has been opened.
    ; It can only be "bombable", "key", "key 2", or "shutter".
    ;
    ;
    ; Save provisional door face in Y register.
    moveq   #0,D3
    move.b  D0,D3
    move.b  (A5)+,D0  ; PLA
    move.b  D0,-(A5)  ; PHA
    moveq   #0,D2
    move.b  D0,D2
    move.b  D3,D0
    ; If provisional door face is not for a shutter, then
    ; it's for a "key" or "bombable". So, set the door's flag.
    ;
    ; Else it is for a shutter. Go set provisional door face to 4.
    ;
    cmpi.b  #$07,D0
    beq  _anon_z05_111
    move.b  D0,-(A5)  ; PHA
    jsr     SetDoorFlag
    move.b  (A5)+,D0  ; PLA
    ; If the provisional door face = 8 (closed "bombable"),
    ; then go make it 9 (open "bombable").
    ; Else make it 4 (open "door").
    ;
    cmpi.b  #$08,D0
    beq  _L_z05_L_LayOutDoors_LoopHalves_SetPF9
_anon_z05_111:
    moveq   #4,D0
    even
_L_z05_L_LayOutDoors_LoopHalves_DoneOpenPF:
    ; For opened doors, the provisional door face has become:
    ;
    ; DA PF Meaning
    ; -------------
    ; 0  4  open
    ; 1  1  wall
    ; 2  2  false wall
    ; 3  3  false wall 2
    ; 4  9  bombable
    ; 5  4  key
    ; 6  4  key 2
    ; 7  4  shutter
    ;
    ;
    ; If handling the first half [06], then calculate OpenDoorwayMask.
    ;
    moveq   #0,D2
    move.b  ($0006,A4),D2
    beq  _anon_z05_112
    moveq   #0,D2
    move.b  ($000B,A4),D2
    move.b  D0,-(A5)  ; PHA
    jsr     FindDoorAttrByDoorBit
    jsr     CalcOpenDoorwayMask
    move.b  (A5)+,D0  ; PLA
_anon_z05_112:
    ; If provisional door face < 4 (any wall), then go loop another half,
    ; because the visible door face is already a wall.
    ;
    cmpi.b  #$04,D0
    bcs  _L_z05_L_LayOutDoors_LoopHalves_NextLoopDoorHalf
    ; For all other provisional face values, calculate:
    ; door face := provisional face - 3
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$03,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$03
    eori    #$10,CCR  ; restore X = 6502 C
    moveq   #0,D3
    move.b  D0,D3
    ; Furthermore, if the latest provisional door face >= 3, then
    ; subtract one.
    ;
    cmpi.b  #$03,D3
    bcs  _anon_z05_113
    subq.b  #1,D3
_anon_z05_113:
    ; Now Y holds the door face index (DFC closed, DFO opened) for the door type (DT).
    ;
    ; DT DFC DFO Meaning
    ; ------------------
    ; 0  1   1   open
    ; 4  4   5   bombable
    ; 5  2   1   key
    ; 6  2   1   key 2
    ; 7  3   1   shutter
    ;
    ;
    ; Get the direction index.
    move.b  (A5)+,D0  ; PLA
    move.b  D0,-(A5)  ; PHA
    jsr     FetchDoorAddrsFaceTilesSrcAndPlayAreaDst
    ; If handling the second half, then offset to the second half
    ; of the tiles.
    ;
    move.b  ($0006,A4),D0
    bne  _anon_z05_114
    lea     (DirIndexToDoorSecondHalfOffsets).l,A0
    move.b  (A0,D2.W),D0
    jsr     AddToInt16At0
    moveq   #6,D0
    jsr     AddToInt16At2
_anon_z05_114:
    ; Fix Y at 0 for copying source tiles to destination.
    ; Pointers will be incremented instead of Y.
    moveq   #0,D3
    lea     (DirIndexToDoorColumnCount).l,A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0005,A4)
    even
_L_z05_L_LayOutDoors_LoopHalves_LoopColumn:
    ; For each column (3 or 2), indexed by [05] down to 1:
    ;
    move.b  (A5)+,D0  ; PLA
    move.b  D0,-(A5)  ; PHA
    moveq   #0,D2
    move.b  D0,D2
    ; For each row (2 or 3) in the door, indexed by X,
    ; starting from highest index down to 0:
    ;
    lea     (DirIndexToDoorRowCountMinusOne).l,A0
    move.b  (A0,D2.W),D0
    moveq   #0,D2
    move.b  D0,D2
    even
_L_z05_L_LayOutDoors_LoopHalves_LoopRowTile:
    move.b  ($02,A4),D1   ; ptr lo
    move.b  ($03,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4
    ext.l   D4
    add.l   #NES_RAM,D4
    movea.l D4,A0
    move.b  D0,(A0,D3.W)     ; STA ($nn),Y
    jsr     Add1ToInt16At2
    lea     (NextDoorTileOffsets).l,A0
    move.b  (A0,D2.W),D0
    jsr     AddToInt16At0
    ; If we're at the last row, and the direction is horizontal (< 2), then
    ; go 1 more tile down, to start the next column at the right place.
    ; We have to compensate for the fact that E/W doors are 
    ; shorter vertically than N/S doors.
    cmpi.b  #$00,D2
    bne  _anon_z05_115
    move.b  (A5)+,D0  ; PLA
    move.b  D0,-(A5)  ; PHA
    cmpi.b  #$02,D0
    bcc  _anon_z05_115
    jsr     Add1ToInt16At0
_anon_z05_115:
    ; Bottom of the tile row copying loop.
    ; Decrement the row index.
    ;
    subq.b  #1,D2
    bpl  _L_z05_L_LayOutDoors_LoopHalves_LoopRowTile
    ; Bottom of the column copying loop.
    ; Decrease the column counter.
    ;
    subq.b  #1,($0005,A4)
    bne  _L_z05_L_LayOutDoors_LoopHalves_LoopColumn
    even
_L_z05_L_LayOutDoors_LoopHalves_NextLoopDoorHalf:
    ; Bottom of the door halves loop.
    ;
    move.b  (A5)+,D0  ; PLA
    moveq   #0,D2
    move.b  D0,D2
    subq.b  #1,($0006,A4)
    bmi  _anon_z05_116
    jmp     L_LayOutDoors_LoopHalves

_anon_z05_116:
    ; Bottom of the door loop.
    ; Decrement door index.
    ;
    subq.b  #1,D2
    bpl.s  __far_z_05_0090
    jmp  L165D4_Exit
__far_z_05_0090:
    jmp     L_LayOutDoors_LoopDoors

; Params:
; A: direction index
; Y: face index
;
; Returns:
; X: direction index
; [$00:01]: address of door inside play area tile map
; [$02:03]: address of door tiles for direction and face
;
    even
FetchDoorAddrsFaceTilesSrcAndPlayAreaDst:
    moveq   #0,D2
    move.b  D0,D2
    lea     (DoorFaceTilesAddrsLo).l,A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0002,A4)
    lea     (DoorFaceTilesAddrsHi).l,A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0003,A4)
    lea     (PlayAreaDoorFaceAddrsLo).l,A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0000,A4)
    lea     (PlayAreaDoorFaceAddrsHi).l,A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0001,A4)
_anon_z05_117:
    subq.b  #1,D3
    bne.s  __far_z_05_0091
    jmp  L165D4_Exit
__far_z_05_0091:
    moveq   #12,D0
    jsr     AddToInt16At2
    jmp     _anon_z05_117

    even
L165D4_Exit:
    rts

    even
HorizontalDoorFaceIndexes:
    dc.b    $01, $03, $06, $08, $03, $05, $08, $0A
    dc.b    $03, $06, $04, $07, $05, $08

    even
HorizontalDoorFaceIndexesBaseOffsets:
    dc.b    $00, $04, $08, $0A

    even
DoorVramAddrsHi:
    dc.b    $22, $22, $23, $21

    even
DoorVramAddrsLo:
    dc.b    $5C, $42, $4F, $4F

    even
DoorNextRoomIdOffsets:
    dc.b    $01, $FF, $10, $F0

    even
UpdateDoors:
    ; If mode = $12, or door timer <> 0, or door command = 0,
    ; then return.
    ;
    move.b  ($0012,A4),D0
    cmpi.b  #$12,D0
    bne.s  __far_z_05_0092
    jmp  L165D4_Exit
__far_z_05_0092:
    move.b  ($0027,A4),D0
    beq.s  __far_z_05_0093
    jmp  L165D4_Exit
__far_z_05_0093:
    move.b  ($0054,A4),D0
    bne.s  __far_z_05_0094
    jmp  L165D4_Exit
__far_z_05_0094:
    ; Turn the door command into the desired open or closed state
    ; to store in [08].
    ;
    ; cmd:  7 6 3 2 
    ; [08]: 2 0 0 0
    ;
    ; There are other combinations, but 2, 3, 6, and 7 are the only
    ; commands intended to be used.
    ;
    ; 3 is the end state of 2: close
    ; 7 is the end state of 6: open
    ;
    andi.b #$07,D0
    moveq   #1,D3
    move.b  D3,($0002,A4)
    move.b  ($0002,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    beq  _anon_z05_118
    lsr.b  #1,D0   ; LSR A
_anon_z05_118:
    cmpi.b  #$02,D0
    bne  _anon_z05_119
    ; Command 2 sets Link's timer to $30.
    ;
    moveq   #48,D3
    move.b  D3,($0028,A4)
_anon_z05_119:
    andi.b #$03,D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$01,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$01
    eori    #$10,CCR  ; restore X = 6502 C
    andi.b #$02,D0
    move.b  D0,($0008,A4)
    ; The command to close a key door or bombable wall does not
    ; do anything.
    ;
    move.b  ($0054,A4),D0
    cmpi.b  #$05,D0
    bcc  _anon_z05_120
    move.b  ($0055,A4),D0
    move.b  D0,($0002,A4)
    jsr     FindDoorAttrByDoorBit
    cmpi.b  #$07,D0
    beq  _anon_z05_120
    jmp     L_ResetDoorCmdAndLayOutDoors

_anon_z05_120:
    ; TriggeredDoorCmd >= 5 or door type = 7
    ;
    ; Shutters and the commands to open a door always change
    ; tiles.
    ;
    jsr     PrepareWriteHorizontalDoorTransferRecords
    even
_L_z05_UpdateDoors_LoopTransferRec:
    ; Copy [06] to [04] for the call to write tiles below.
    ; We need to remember how many tiles need to be copied
    ; in each transfer record.
    ;
    move.b  ($0006,A4),D0
    move.b  D0,($0004,A4)
    ; Write the transfer record header for the door.
    ;
    ;
    ; VRAM address high byte of door
    move.b  ($0000,A4),D0
    lea     ($0302,A4),A0
    move.b  D0,(A0,D2.W)
    addq.b  #1,D2
    move.b  ($0001,A4),D0
    lea     ($0302,A4),A0
    move.b  D0,(A0,D2.W)
    addq.b  #1,D2
    move.b  ($0006,A4),D0
    lea     ($0302,A4),A0
    move.b  D0,(A0,D2.W)
    addq.b  #1,D2
_anon_z05_121:
    ; Write two tiles in a short loop indexed by [04].
    ;
    jsr     WriteDoorFaceTileHorizontally
    bne  _anon_z05_121
    ; OR the low VRAM address with $20 to go down one row
    ; in order to work on the second row of door tiles.
    ;
    moveq   #32,D0
    move.b  ($0001,A4),D1
    or.b  D1,D0
    move.b  D0,($0001,A4)
    ; Bottom of the loop.
    ; Loop again to write the second transfer record for the
    ; second pair of door tiles, if [05] has not reached 0.
    ;
    subq.b  #1,($0005,A4)
    bne  _L_z05_UpdateDoors_LoopTransferRec
    ; Write the end marker, and update buffer length.
    ;
    move.b  #$FF,D0
    lea     ($0302,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  D2,D0
    move.b  D0,($0301,A4)
    ; Increment the command.
    ;
    addq.b  #1,($0054,A4)
    ; If (new command AND 3) = 0, go update door flags and masks,
    ; and resetting the door command.
    ; This ends up catching original states 3 and 7.
    ;
    ; Else set door timer to 8 and return.
    ;
    move.b  ($0054,A4),D0
    andi.b #$03,D0
    beq  _anon_z05_122
    moveq   #8,D0
    move.b  D0,($0027,A4)
    rts

_anon_z05_122:
    ; If the door command = 4 after incrementing it, then
    ; it was 3 (close door). So:
    ; 1. reset this door's flag
    ; 2. remove it from the opened door mask
    ; 3. reset the door command
    ; 4. go lay out doors in the play area map
    ;
    move.b  ($0054,A4),D0
    cmpi.b  #$04,D0
    bne  _anon_z05_123
    moveq   #0,D2
    move.b  ($0009,A4),D2
    jsr     ResetDoorFlag
    move.b  ($0055,A4),D0
    eori.b #$0F,D0
    move.b  ($00EE,A4),D1
    and.b  D1,D0
    even
L_SetOpenedDoorMaskAndResetCmdAndLayOutDoors:
    move.b  D0,($00EE,A4)
    even
L_ResetDoorCmdAndLayOutDoors:
    moveq   #0,D0
    move.b  D0,($0054,A4)
    jmp     LayOutDoors

_anon_z05_123:
    ; Door command <> 4.
    ; It must be 8, which means it was 7: open door.
    ;
    ; If the door is a shutter (7), then go add the door to the
    ; opened door mask, reset door command, and lay out doors.
    ;
    move.b  ($0055,A4),D0
    move.b  D0,($0002,A4)
    jsr     FindDoorAttrByDoorBit
    cmpi.b  #$07,D0
    beq  _anon_z05_124
    ; Else the door is not a shutter.
    ;
    ;
    ; [09] door direction index
    moveq   #0,D2
    move.b  ($0009,A4),D2
    jsr     SetDoorFlag
    ; Get the next room's ID.
    ;
    move.b  D3,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     (DoorNextRoomIdOffsets).l,A0
    move.b  (A0,D2.W),D1
    addx.b  D1,D0   ; ADC DoorNextRoomIdOffsets,X
    moveq   #0,D3
    move.b  D0,D3
    ; Flip the door direction index.
    ;
    move.b  D2,D0
    eori.b #$01,D0
    moveq   #0,D2
    move.b  D0,D2
    ; Set the door flag for the opposite door in the next room.
    ;
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    lea     (LevelMasks).l,A0
    move.b  (A0,D2.W),D1
    or.b  D1,D0
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4
    ext.l   D4
    add.l   #NES_RAM,D4
    movea.l D4,A0
    move.b  D0,(A0,D3.W)     ; STA ($nn),Y
_anon_z05_124:
    ; Add the door to the opened door mask, reset door command,
    ; and lay out doors.
    ;
    move.b  ($0055,A4),D0
    move.b  ($00EE,A4),D1
    or.b  D1,D0
    jmp     L_SetOpenedDoorMaskAndResetCmdAndLayOutDoors

; Params:
; [08]: 0 if closed
;
; Returns:
; X: current length of dynamic transfer buf
; [00]: door VRAM address high byte
; [01]: door VRAM address low byte
; [02:03]: address of door tiles for direction and face
; [05]: 2, the number of transfer records to write
; [06]: 2, the number of tiles in each record
; [07]: 0, the first index of a tile to transfer
; [09]: door direction index
;
; Note that this routine is called with triggered doors:
; doors that can change state. Their door type numbers are >= 4.
;
; If this routine were ever called with a fixed door
; ("open", "wall", or "false"), then it would produce non-sensical
; values for the door face.
;
;
; If triggered door type >= 5 (keys and shutter), play door sound.
;
    even
PrepareWriteHorizontalDoorTransferRecords:
    move.b  ($0055,A4),D0
    move.b  D0,($0002,A4)
    jsr     FindDoorAttrByDoorBit
    cmpi.b  #$05,D0
    bcs  _anon_z05_125
    move.b  D0,-(A5)  ; PHA
    moveq   #4,D0
    jsr     PlaySample
    move.b  (A5)+,D0  ; PLA
_anon_z05_125:
    ; Calculate the door face index in three parts.
    ;
    ; First, turn door type 4 into 8, and 1 into 4
    ; (provisional face index in Y register).
    ;
    cmpi.b  #$04,D0
    bne  _anon_z05_126
    moveq   #8,D0
_anon_z05_126:
    cmpi.b  #$01,D0
    bne  _anon_z05_127
    moveq   #4,D0
_anon_z05_127:
    ; Second, subtract 3 from provisional face index.
    ;
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$03,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$03
    eori    #$10,CCR  ; restore X = 6502 C
    moveq   #0,D3
    move.b  D0,D3
    ; Lastly, if the door is closed ([08] = 0) and provisional
    ; face index >= 3, then subtract 1 from it.
    ;
    ; But if open ([08] <> 0) and provisional face index <> 5,
    ; then make it 1.
    ;
    move.b  ($0008,A4),D0
    beq  _anon_z05_128
    cmpi.b  #$05,D3
    beq  _L_z05_PrepareWriteHorizontalDoorTransferRecords_MakeForwardIndex
    moveq   #1,D3
_anon_z05_128:
    cmpi.b  #$03,D3
    bcs  _L_z05_PrepareWriteHorizontalDoorTransferRecords_MakeForwardIndex
    subq.b  #1,D3
    even
_L_z05_PrepareWriteHorizontalDoorTransferRecords_MakeForwardIndex:
    ; The routine that returned the door type also returned its
    ; reverse direction index in [03].
    ;
    ; We want a forward direction index. So, subtract [03] from 3.
    ;
    moveq   #3,D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  ($0003,A4),D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC $03
    eori    #$10,CCR  ; restore X = 6502 C
    ; Call this to put the address of door face tiles in [02:03].
    ;
    jsr     FetchDoorAddrsFaceTilesSrcAndPlayAreaDst
    ; Return the address of the door in the nametable in [01:00].
    ; Note the order is reversed, as usual with VRAM addresses.
    ;
    lea     (DoorVramAddrsHi).l,A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0000,A4)
    lea     (DoorVramAddrsLo).l,A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0001,A4)
    ; Return the direction of the door in [09], and the dynamic
    ; transfer buf length in X register.
    ;
    move.b  D2,($0009,A4)
    moveq   #0,D2
    move.b  ($0301,A4),D2
    ; Return some hardcoded values in [05], [06], [07]. See the comments above.
    ;
    moveq   #0,D0
    move.b  D0,($0007,A4)
    moveq   #2,D0
    move.b  D0,($0006,A4)
    move.b  D0,($0005,A4)
    eori    #$01,CCR  ; normalize C to 6502 polarity before RTS
    rts

    even
