    andi.b #$70,D0
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    move.b  ($0008,A4),D1
    cmp.b   D1,D0
    beq  _anon_z05_130
    addq.b  #1,($0008,A4)
    jmp     _L_z05_LayoutUWFloor_NextLoopSquareRow

_anon_z05_130:
