; Params:
; A: primary square
; Y: offset from [$00:01]
; [$00:01]: pointer to play area
;
    even
WriteSquareUW:
    cmpi.b  #$70,D0
    bcs  _L_z05_WriteSquareUW_WriteType2
    cmpi.b  #$F3,D0
    bcc  _L_z05_WriteSquareUW_WriteType2
    ; Type 1 square.
    ; Primary is the first tile. Next 3 tiles in CHR form the rest of the square.
    ; Primary >= $70 and < $F3.
    ;
    moveq   #0,D2
    move.b  D0,D2
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4
    ext.l   D4
    add.l   #NES_RAM,D4
    movea.l D4,A0
    move.b  D0,(A0,D3.W)     ; STA ($nn),Y
    addq.b  #1,D3
    addq.b  #1,D2
    move.b  D2,D0
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4
    ext.l   D4
    add.l   #NES_RAM,D4
    movea.l D4,A0
    move.b  D0,(A0,D3.W)     ; STA ($nn),Y
    move.b  D3,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$15,D1
    addx.b  D1,D0   ; ADC #$15 (X flag = 6502 C)
    moveq   #0,D3
    move.b  D0,D3
    addq.b  #1,D2
    move.b  D2,D0
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4
    ext.l   D4
    add.l   #NES_RAM,D4
    movea.l D4,A0
    move.b  D0,(A0,D3.W)     ; STA ($nn),Y
    addq.b  #1,D2
    move.b  D2,D0
    even
_L_z05_WriteSquareUW_WriteLastTile:
    addq.b  #1,D3
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4
    ext.l   D4
    add.l   #NES_RAM,D4
    movea.l D4,A0
    move.b  D0,(A0,D3.W)     ; STA ($nn),Y
    rts

    even
_L_z05_WriteSquareUW_WriteType2:
    ; Type 2 square.
    ; Primary is a tile used for the whole square.
    ; Primary < $70 or >= $F3.
    ;
    ;
    ; Write tile to (col, row).
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4
    ext.l   D4
    add.l   #NES_RAM,D4
    movea.l D4,A0
    move.b  D0,(A0,D3.W)     ; STA ($nn),Y
    addq.b  #1,D3
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4
    ext.l   D4
    add.l   #NES_RAM,D4
    movea.l D4,A0
    move.b  D0,(A0,D3.W)     ; STA ($nn),Y
    move.b  D0,-(A5)  ; PHA
    move.b  D3,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$15,D1
    addx.b  D1,D0   ; ADC #$15 (X flag = 6502 C)
    moveq   #0,D3
    move.b  D0,D3
    move.b  (A5)+,D0  ; PLA
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4
    ext.l   D4
    add.l   #NES_RAM,D4
    movea.l D4,A0
    move.b  D0,(A0,D3.W)     ; STA ($nn),Y
    jmp     _L_z05_WriteSquareUW_WriteLastTile

