FindAndCreatePushBlockObject:
    ; Reset block state and direction.
    ;
    moveq   #0,D0
    move.b  D0,($00B7,A4)
    move.b  D0,($00A3,A4)
    ; If the unique room ID is $21, then
    ; put the push block object at ($40, $80), and go set the type.
    ;
    ; TODO: Where is room layout $21 used?
    ;
    jsr     GetUniqueRoomId
    cmpi.b  #$21,D0
    bne  _anon_z05_132
    moveq   #64,D0
    move.b  D0,($007B,A4)
    lsl.b  #1,D0   ; ASL A
    move.b  D0,($008F,A4)
    jmp     _L_z05_FindAndCreatePushBlockObject_SetType

_anon_z05_132:
    ; Look for a block tile in row $A of play area, starting in column 4.
    ;
    moveq   #8,D2
    moveq   #10,D3
    even
_L_z05_FindAndCreatePushBlockObject_LoopColumn:
    lea     (PlayAreaColumnAddrs).l,A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0000,A4)
    lea     (PlayAreaColumnAddrs+1).l,A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0001,A4)
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    cmpi.b  #$B0,D0
    beq  _L_z05_FindAndCreatePushBlockObject_Found
    addq.b  #1,D2
    addq.b  #1,D2
    addq.b  #1,D2
    addq.b  #1,D2
    cmpi.b  #$34,D2
    bne  _L_z05_FindAndCreatePushBlockObject_LoopColumn
    even
_L_z05_FindAndCreatePushBlockObject_Found:
    ; The block was found in a column with an address at
    ; offset %X in column table. So the column number would
    ; be (%X/2), and X coordinate ((%X/2)*8). That means
    ; multiplying %X by 4.
    move.b  D2,D0
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    move.b  D0,($007B,A4)
    move.b  #$90,D0
    move.b  D0,($008F,A4)
    even
_L_z05_FindAndCreatePushBlockObject_SetType:
    moveq   #104,D0
    move.b  D0,($035A,A4)
    rts

