    moveq   #26,D0
    move.b  D0,($0000,A4)
    moveq   #101,D0
    move.b  D0,($0001,A4)
    moveq   #0,D2
    move.b  ($00E8,A4),D2
    subq.b  #1,D2
    move.b  D2,D0
    moveq   #0,D3
    move.b  ($0301,A4),D3
    lea     ($0303,A4),A0
