LayoutRoomOrCaveOW:
    moveq   #5,D0
    jsr     _copy_bank_to_window   ; PATCH P33b: force window bank 5
    move.b  (NES_SRAM+$0BAF).l,D0
    move.b  D0,($0008,A4)
    move.b  (NES_SRAM+$0BB0).l,D0
    move.b  D0,($0009,A4)
    jsr     FetchTileMapAddr
    moveq   #5,D0
    jsr     _copy_bank_to_window   ; PATCH P33c: re-pin bank 5 after FetchTileMapAddr
    move.b  ($00,A4),D1                    ; PATCH P35a: workbuf ptr lo
    move.b  ($01,A4),D4                    ; PATCH P35a: workbuf ptr hi
    andi.w  #$00FF,D1
    lsl.w   #8,D4
    or.w    D1,D4
    ext.l   D4
    add.l   #NES_RAM,D4
    move.l  D4,($00FF110A).l              ; PATCH P35a: cached OW workbuf ptr
    ; For each column in room, indexed by [06]:
    ;
    moveq   #0,D0
    move.b  D0,($000C,A4)
    move.b  D0,($0006,A4)
    even
_L_z05_LayoutRoomOrCaveOW_LoopColumnOW:
    moveq   #0,D3
    move.b  ($0006,A4),D3
    movea.l ($00FF1102).l,A2            ; PATCH P34f: reload call-safe layout ptr
    move.b  (A2,D3.W),D0                ; PATCH P34f: descriptor read (NES parity)
    andi.b #$F0,D0
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    moveq   #0,D2
    move.b  D0,D2
    ; Load the column table address for this descriptor in [$04:05].
    ;
    add.w   D2,D2                       ; PATCH P34h: 2-byte -> 4-byte index
    lea     (ColumnDirectoryOWPtrs).l,A0
    movea.l (A0,D2.W),A3                ; PATCH P34h: direct OW column ptr
    move.l  A3,($00FF1106).l            ; PATCH P34h: cache call-safe OW column ptr
    move.b  (A2,D3.W),D0                ; PATCH P34f: descriptor reread for low nibble
    andi.b #$0F,D0
    moveq   #0,D2
    move.b  D0,D2
    move.b  #$FF,D3
_anon_z05_142:
    ; Look for the beginning of a column.
    ;
    addq.b  #1,D3
    movea.l ($00FF1106).l,A3            ; PATCH P34h: reload OW column ptr
    move.b  (A3,D3.W),D0                ; PATCH P34h: direct OW column read
    bpl  _anon_z05_142
    subq.b  #1,D2
    bpl  _anon_z05_142
    ; We found the column.
    ;
    movea.l ($00FF1106).l,A3            ; PATCH P34h: reload OW column ptr
    adda.w  D3,A3                       ; PATCH P34h: advance to found column
    move.l  A3,($00FF1106).l            ; PATCH P34h: store updated ptr
    moveq   #0,D0
    move.b  D0,($0007,A4)
    even
_L_z05_LayoutRoomOrCaveOW_LoopSquareOW:
    moveq   #0,D3
    movea.l ($00FF1106).l,A3            ; PATCH P34h: reload OW column ptr
    move.b  (A3,D3.W),D0                ; PATCH P34h: direct OW column read
    andi.b #$3F,D0
    move.b  D0,($000D,A4)
    moveq   #0,D2
    move.b  D0,D2
    lea     (PrimarySquaresOW).l,A0
    move.b  (A0,D2.W),D0
    move.b  D0,-(A5)  ; PHA
    moveq   #0,D3
    move.b  ($00EB,A4),D3
    move.b  ($08,A4),D1   ; ptr lo
    move.b  ($09,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    andi.b #$80,D0
    beq  _L_z05_LayoutRoomOrCaveOW_SkipSecret
    move.b  (A5)+,D0  ; PLA
    ; The secret was found in this room.
    ;
    cmpi.b  #$E7,D0
    beq  _L_z05_LayoutRoomOrCaveOW_MakeStairs
    cmpi.b  #$E6,D0
    beq  _L_z05_LayoutRoomOrCaveOW_MakeCave
    cmpi.b  #$EA,D0
    bne  _L_z05_LayoutRoomOrCaveOW_RestoreSquare
    even
_L_z05_LayoutRoomOrCaveOW_MakeStairs:
    ; This is a tree or a special armos ($EA).
    ; Set the primary to stairs ($70), and square index to the
    ; first value ($10) for a type 1 square.
    ;
    moveq   #16,D0
    move.b  D0,($000D,A4)
    moveq   #112,D0
    bne  _L_z05_LayoutRoomOrCaveOW_RestoreSquare
    even
_L_z05_LayoutRoomOrCaveOW_MakeCave:
    ; This is a rock wall. Turn it into a cave entrance.
    ;
    moveq   #12,D0
    move.b  D0,($000D,A4)
    even
_L_z05_LayoutRoomOrCaveOW_RestoreSquare:
    move.b  D0,-(A5)  ; PHA
    even
_L_z05_LayoutRoomOrCaveOW_SkipSecret:
    move.b  (A5)+,D0  ; PLA    jsr     CheckTileObject
    jsr     WriteSquareOW_P35             ; PATCH P35b: OW direct workbuf write
    movea.l ($00FF110A).l,A1              ; PATCH P35a: advance cached OW workbuf ptr
    addq.l  #2,A1
    move.l  A1,($00FF110A).l
    move.l  A1,D4
    sub.l   #NES_RAM,D4
    move.b  D4,($0000,A4)
    lsr.l   #8,D4
    move.b  D4,($0001,A4)
    moveq   #0,D3
    movea.l ($00FF1106).l,A3            ; PATCH P34h: reload OW column ptr
    move.b  (A3,D3.W),D0                ; PATCH P34h: direct OW column read
    andi.b #$40,D0
    beq  _L_z05_LayoutRoomOrCaveOW_NextSquare
    move.b  ($000C,A4),D1
    eor.b  D1,D0
    move.b  D0,($000C,A4)
    bne  _anon_z05_143
    even
_L_z05_LayoutRoomOrCaveOW_NextSquare:
    movea.l ($00FF1106).l,A3            ; PATCH P34h: reload OW column ptr
    addq.l  #1,A3                       ; PATCH P34h: advance to next column byte
    move.l  A3,($00FF1106).l            ; PATCH P34h: store updated ptr
_anon_z05_143:
    addq.b  #1,($0007,A4)
    move.b  ($0007,A4),D0
    cmpi.b  #$0B,D0
    bne  _L_z05_LayoutRoomOrCaveOW_LoopSquareOW    ; At the end of a column, we've reached the top of the next one.
    ; Move one more column over to get to the next square column.
    movea.l ($00FF110A).l,A1              ; PATCH P35a: end-column OW workbuf advance
    adda.w  #$0016,A1
    move.l  A1,($00FF110A).l
    move.l  A1,D4
    sub.l   #NES_RAM,D4
    move.b  D4,($0000,A4)
    lsr.l   #8,D4
    move.b  D4,($0001,A4)
    addq.b  #1,($0006,A4)
    move.b  ($0006,A4),D0
    cmpi.b  #$10,D0
    bcs.s  __far_z_05_0098
    jmp  L16AF0_Exit
__far_z_05_0098:
    jmp     _L_z05_LayoutRoomOrCaveOW_LoopColumnOW

; Params:
; A: primary square
;
; Returns:
; A: primary square corresponding to tile object, else argument
;
;
; Find the index X corresponding to the primary square: $E5  => 0; $EA => 5.
;
