CheckTileObject:
    move.b  #$EA,D2
    move.b  D2,($000A,A4)
    moveq   #5,D2
_anon_z05_144:
    move.b  ($000A,A4),D1
    cmp.b   D1,D0
    beq  _anon_z05_145
    subq.b  #1,($000A,A4)
    subq.b  #1,D2
    bpl  _anon_z05_144
    bpl.s  __far_z_05_0099
    jmp  L16AF0_Exit
__far_z_05_0099:
_anon_z05_145:
    lea     (TileObjectPrimarySquaresOW).l,A0
    move.b  (A0,D2.W),D0
    move.b  D0,-(A5)  ; PHA
    lea     (TileObjectTypes).l,A0
    move.b  (A0,D2.W),D0
    move.b  D0,($052B,A4)
    move.b  ($0006,A4),D0
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    move.b  D0,($052C,A4)
    move.b  ($0007,A4),D0
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$40,D1
    addx.b  D1,D0   ; ADC #$40 (X flag = 6502 C)
    move.b  D0,($052D,A4)
    move.b  (A5)+,D0  ; PLA
    even
