    jsr     GetShortcutOrItemXY
    ; Divide X coordinate by 4 to get offset into column address table.
    ; Think of it this way. Divide X by 8 to get tile column number.
    ; Then multiply by 2 to turn it into an offset for an address.
    ;
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    moveq   #0,D2
    move.b  D0,D2
    lea     (PlayAreaColumnAddrs).l,A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0000,A4)
    lea     (PlayAreaColumnAddrs+1).l,A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0001,A4)
    move.b  D3,D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$40,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$40
    eori    #$10,CCR  ; restore X = 6502 C
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    moveq   #0,D3
    move.b  D0,D3
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    cmpi.b  #$C4,D0
    beq  _L_z05_CheckShortcut_WriteStairs
    cmpi.b  #$BC,D0
    beq  _L_z05_CheckShortcut_Exit
    cmpi.b  #$D8,D0
    bne  _L_z05_CheckShortcut_WriteStairs
    move.b  ($052B,A4),D0
    cmpi.b  #$62,D0
    beq  _L_z05_CheckShortcut_WriteStairs
    ; Else make the tile object nothing, and write a black tile.
    ; But this branch seems to be unused.
    moveq   #0,D0
    move.b  D0,($052B,A4)
    moveq   #12,D0
    move.b  D0,($000D,A4)
    even
_L_z05_CheckShortcut_Write:
    jsr     WriteSquareOW
    even
_L_z05_CheckShortcut_Exit:
    rts

    even
_L_z05_CheckShortcut_WriteStairs:
    moveq   #16,D0
    move.b  D0,($000D,A4)
    moveq   #112,D0
    bne  _L_z05_CheckShortcut_Write
    even
ChangePlayMapSquareOW:
    move.b  D2,D0
    move.b  D0,-(A5)  ; PHA
    ; We're dealing with squares.
    ; So, align the object's X coordinate with 16 pixels.
    ;
    move.b  ($70,A4,D2.W),D0
    andi.b #$F0,D0
    ; Divide it by 4 to get the offset of the address of the column
    ; in play area map.
    ;
    ; The calculation is: address offset = (X / 8) * 2
    ; 8 for the width of the column; 2 for the width of the address
    ;
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    moveq   #0,D2
    move.b  D0,D2
    ; Store the address of the column in [00:01].
    ;
    lea     (PlayAreaColumnAddrs).l,A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0000,A4)
    lea     (PlayAreaColumnAddrs+1).l,A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0001,A4)
    move.b  (A5)+,D0  ; PLA
    move.b  D0,-(A5)  ; PHA
    moveq   #0,D2
    move.b  D0,D2
    ; Align the object's Y coordinate with 16 pixels.
    ;
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$F0,D0
    ; Subtract $40 for the status bar; and divide by 8 for
    ; the height of each row.
    ;
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$40,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$40
    eori    #$10,CCR  ; restore X = 6502 C
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    ; Add this row offset to the column address.
    ;
    jsr     AddToInt16At0
    ; Assume that we'll write a type 1 square with primary square
    ; taken from [05]. If so, the square index doesn't matter
    ; as long as >= $10. See WriteSquareOW.
    ;
    moveq   #0,D3
    moveq   #16,D2
    move.b  ($0005,A4),D0
    ; If tile < $27 or >= $F3, we'll write a type 3 square.
    ; So, we have to look up the square index corresponding
    ; to primary square/tile in [05].
    ;
    ; Look in primary square table from $E to 1. If a match is found,
    ; then the X register will have the square index value.
    ;
    cmpi.b  #$27,D0
    bcs  _anon_z05_148
    cmpi.b  #$F3,D0
    bcs  _L_z05_ChangePlayMapSquareOW_Write
_anon_z05_148:
    moveq   #14,D2
_anon_z05_149:
    lea     (PrimarySquaresOW).l,A0
    move.b  (A0,D2.W),D1
    cmp.b   D1,D0
    beq  _L_z05_ChangePlayMapSquareOW_Write
    subq.b  #1,D2
    bne  _anon_z05_149
    even
_L_z05_ChangePlayMapSquareOW_Write:
    ; Write the square.
    ;
    move.b  D2,($000D,A4)
    jsr     WriteSquareOW
    move.b  (A5)+,D0  ; PLA
    moveq   #0,D2
    move.b  D0,D2
    rts

; Returns:
; [$00:01]: address of room tile map
    even
FetchTileMapAddr:
    moveq   #48,D0
    move.b  D0,($0000,A4)
    moveq   #101,D0
    move.b  D0,($0001,A4)
    rts

