; Description:
; Two sets of 5 elements:
; * left bound for objects
; * right bound for objects
; * up bound for objects
; * down bound for objects
; * first unwalkable tile
;
; The first set is for OW. The second is for UW.
;
    even
ObjectRoomBoundsOW:
    dc.b    $11, $E0, $4E, $CD, $89

    even
ObjectRoomBoundsUW:
    dc.b    $21, $D0, $5E, $BD, $78

    even
SetupObjRoomBounds:
    moveq   #5,D3
    move.b  ($0010,A4),D0
    bne  _anon_z05_153
    ; Reset DoorwayDir and use first set of bounds.
    ;
    ;
    ; Offset of first set of bounds.
    moveq   #0,D3
    move.b  D3,($0053,A4)
_anon_z05_153:
    moveq   #0,D2
_anon_z05_154:
    lea     (ObjectRoomBoundsOW).l,A0
    move.b  (A0,D3.W),D0
    lea     ($0346,A4),A0
    move.b  D0,(A0,D2.W)
    addq.b  #1,D3
    addq.b  #1,D2
    cmpi.b  #$05,D2
    bne  _anon_z05_154
    rts

    even
LeavingRoomRelativePositions:
