    move.b  ($005E,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$1A,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$1A
    eori    #$10,CCR  ; restore X = 6502 C
    lsr.b  #1,D0   ; LSR A
    moveq   #0,D2
    move.b  D0,D2
    moveq   #15,D3
    even
_L_z05_Submenu_WriteSheetMapRowTransferRecord_MaskRooms:
    ; For each element ($10) in the row, starting from $F:
    ; If the current row is set in the submenu map mask,
    ; then replace the tile with $F5, a blank map tile.
    ;
    lea     (NES_SRAM+$0BBD).l,A0
    move.b  (A0,D3.W),D0
    lea     (MapRowMasks).l,A0
    move.b  (A0,D2.W),D1
    and.b  D1,D0
    bne  _anon_z05_201
    move.b  #$F5,D0
    lea     ($0305,A4),A0
    move.b  D0,(A0,D3.W)
_anon_z05_201:
    subq.b  #1,D3
    bpl  _L_z05_Submenu_WriteSheetMapRowTransferRecord_MaskRooms
    rts

; Returns:
; A: 0 if compass of current level is missing.
;
;
; Check compasses.
    even
HasCompass:
    moveq   #16,D2
    bne  _anon_z05_202
; Returns:
; A: 0 if map of current level is missing.
;
;
; Check maps.
    even
HasMap:
    moveq   #17,D2
_anon_z05_202:
    move.b  ($0010,A4),D0
    beq  _L_z05_HasMap_Exit
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$01,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$01
    eori    #$10,CCR  ; restore X = 6502 C
    cmpi.b  #$08,D0
    bcs  _anon_z05_203
    addq.b  #1,D2
    addq.b  #1,D2
_anon_z05_203:
    andi.b #$07,D0
    moveq   #0,D3
    move.b  D0,D3
    lea     ($0657,A4),A0
    move.b  (A0,D2.W),D0
    lea     (LevelMasks).l,A0
    move.b  (A0,D3.W),D1
    and.b  D1,D0
    even
_L_z05_HasMap_Exit:
    rts

; Params:
; Y: offset from the third element in dynamic transfer buf
;    to write at (between 1 and $10)
;
;
; Save dynamic transfer buf offset.
    even
Submenu_WriteScanningMapRoomMark:
    move.b  D3,D0
    move.b  D0,-(A5)  ; PHA
    jsr     GetRoomFlags
    move.b  ($00EB,A4),D0
    move.b  D0,-(A5)  ; PHA
    ; Temporarily set current room ID to the room ID we're scanning,
    ; in order to look up its information.
    ;
    move.b  ($005D,A4),D0
    move.b  D0,($00EB,A4)
    ; Set OpenDoorMask to $13, in case the room has not been
    ; visited. $E2 will be added, yielding $F5, which is the blank
    ; map mark tile.
    ;
    moveq   #19,D0
    move.b  D0,($033F,A4)
    ; Get the currently scanned room's visit state.
    ;
    moveq   #0,D3
    move.b  ($00EB,A4),D3
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    andi.b #$20,D0
    ; If it's been visited, then check each of the 4 doors,
    ; and build an open door mask.
    ;
    ; Start with direction up and direction index 3.
    ;
    beq  _L_z05_Submenu_WriteScanningMapRoomMark_WriteMapTile
    moveq   #8,D0
    move.b  D0,($0002,A4)
    moveq   #3,D2
_anon_z05_204:
    jsr     FindDoorAttrByDoorBit
    jsr     CalcOpenDoorwayMask
    subq.b  #1,D2
    move.b  ($0002,A4),D1
    lsr.b  #1,D1   ; LSR $02
    move.b  D1,($0002,A4)
    bne  _anon_z05_204
    even
_L_z05_Submenu_WriteScanningMapRoomMark_WriteMapTile:
    ; Restore current room ID and dynamic buffer offset.
    ;
    move.b  (A5)+,D0  ; PLA
    move.b  D0,($00EB,A4)
    move.b  (A5)+,D0  ; PLA
    moveq   #0,D3
    move.b  D0,D3
    ; The map marks are arranged in the same order as all the
    ; possible values of OpenDoorMask.
    ;
    ; Add $E2 for the first map mark tile, and store it in the
    ; dynamic transfer buf at the current offset.
    ;
    move.b  ($033F,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$E2,D1
    addx.b  D1,D0   ; ADC #$E2 (X flag = 6502 C)
    lea     ($0304,A4),A0
    move.b  D0,(A0,D3.W)
    rts

; Call for each direction index (3 to 0) to build an open doorway mask
; based on doorway type and room flags. Each call will shift the next
; doorway state bit into OpenDoorwayMask.
;
; Params:
; A: door attribute
; X: direction index
;
; Returns:
; A: untouched
;
    even
CalcOpenDoorwayMask:
    moveq   #0,D3
    move.b  D0,-(A5)  ; PHA
    cmpi.b  #$04,D0
    bcs  _L_z05_CalcOpenDoorwayMask_ByDoorType
    ; Else we have to find out the walkability from the room flags.
    ;
    move.b  D2,D0
    move.b  D0,-(A5)  ; PHA
    move.b  D3,D0
    move.b  D0,-(A5)  ; PHA
    jsr     GetRoomFlags
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     (LevelMasks).l,A0
    move.b  (A0,D2.W),D1
    and.b  D1,D0
    beq  _anon_z05_205
    ori     #$11,CCR  ; SEC: set C+X
_anon_z05_205:
    move.b  (A5)+,D0  ; PLA
    moveq   #0,D3
    move.b  D0,D3
    move.b  (A5)+,D0  ; PLA
    moveq   #0,D2
    move.b  D0,D2
    even
_L_z05_CalcOpenDoorwayMask_ShiftIntoMask:
    lea     ($033F,A4),A0
    move.b  (A0,D3.W),D0
    roxl.b  #1,D0   ; ROL A
    andi.b #$0F,D0
    lea     ($033F,A4),A0
    move.b  D0,(A0,D3.W)
    move.b  (A5)+,D0  ; PLA
    rts

    even
_L_z05_CalcOpenDoorwayMask_ByDoorType:
    ; The door attribute indicates the walkability.
    ;
    cmpi.b  #$00,D0
    beq  _L_z05_CalcOpenDoorwayMask_ShiftIntoMask
    andi    #$EE,CCR  ; CLC: clear C+X
    bcc  _L_z05_CalcOpenDoorwayMask_ShiftIntoMask
    even
AddDoorFlagsToCurOpenedDoors:
    jsr     GetRoomFlags
    moveq   #3,D2
    even
_L_z05_AddDoorFlagsToCurOpenedDoors_LoopDoorBit:
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    lea     (LevelMasks).l,A0
    move.b  (A0,D2.W),D1
    and.b  D1,D0
    beq  _anon_z05_206
    move.b  ($00EE,A4),D1
    or.b  D1,D0
    move.b  D0,($00EE,A4)
_anon_z05_206:
    subq.b  #1,D2
    bpl  _L_z05_AddDoorFlagsToCurOpenedDoors_LoopDoorBit
    rts

    even
SplitRoomId:
    move.b  ($00EB,A4),D0
    move.b  D0,-(A5)  ; PHA
    andi.b #$0F,D0
    moveq   #0,D3
    move.b  D0,D3
    move.b  (A5)+,D0  ; PLA
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    moveq   #0,D2
    move.b  D0,D2
    rts

; Params:
; Y: room ID
;
; Returns:
; A: $80 if dark, else 0
;
    even
IsDarkRoom_Bank5:
    move.b  ($0010,A4),D0
    beq  _anon_z05_207
    lea     (NES_SRAM+$0A7E).l,A0
    move.b  (A0,D3.W),D0
    andi.b #$80,D0
_anon_z05_207:
    rts

    even
SubmenuItemXs:
    dc.b    $80, $98, $AC, $B4, $C8, $80, $98, $B0
    dc.b    $C8, $80, $94, $A0, $B0, $C0, $CC, $B0

    even
DrawSubmenuItems:
    ; Look for a magic boomerang, then a wooden boomerang.
    ; If you find one, then draw it.
    ;
    moveq   #30,D2
_anon_z05_208:
    lea     ($0657,A4),A0
    move.b  (A0,D2.W),D0
    bne  _L_z05_DrawSubmenuItems_FoundBoomerang
    subq.b  #1,D2
    cmpi.b  #$1C,D2
    bne  _anon_z05_208
    beq  _L_z05_DrawSubmenuItems_DrawOtherItems
    even
_L_z05_DrawSubmenuItems_FoundBoomerang:
    moveq   #54,D0
    move.b  D0,($0001,A4)
    move.b  #$80,D0
    move.b  D0,($0000,A4)
    move.b  D2,D0
    moveq   #0,D3
    move.b  D0,D3
    jsr     DrawItemInInventory
    even
_L_z05_DrawSubmenuItems_DrawOtherItems:
    ; Look at the rest of the items, starting at index 1.
    ;
    moveq   #1,D2
    even
_L_z05_DrawSubmenuItems_LoopDrawItem:
    lea     ($0657,A4),A0
    move.b  (A0,D2.W),D0
    ; If at the compass item slot, check this level's compass.
    ;
    cmpi.b  #$10,D2
    bne  _anon_z05_209
    jsr     HasCompass
    moveq   #16,D2
_anon_z05_209:
    ; If at the map item slot, check this level's map.
    ;
    cmpi.b  #$11,D2
    bne  _anon_z05_210
    jsr     HasMap
    moveq   #17,D2
_anon_z05_210:
    ; If there are none of this item, then go advance the index and loop again.
    ;
    cmpi.b  #$00,D0
    beq  _L_z05_DrawSubmenuItems_NextLoopDrawItem
    ; If at the letter item slot, look at what's in the potion slot.
    ; If there is a potion, then go advance the index and loop again.
    ; That's because we already prepared sprites for the potion.
    ;
    cmpi.b  #$0F,D2
    bne  _anon_z05_211
    move.b  ($065E,A4),D0
    bne  _L_z05_DrawSubmenuItems_NextLoopDrawItem
_anon_z05_211:
    move.b  D2,D0
    move.b  D0,-(A5)  ; PHA
    moveq   #0,D3
    move.b  D0,D3
    ; Look up and set the X coordinate of this item.
    ;
    lea     (SubmenuItemXs).l,A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0000,A4)
    ; If the item goes in the first selectable row (item slot < 5),
    ; then go set Y coordinate to $36 and draw.
    ;
    moveq   #54,D0
    cmpi.b  #$05,D2
    bcs  _L_z05_DrawSubmenuItems_Draw
    ; If the item goes in the second selectable row (item slot < 9 or = $F),
    ; then go set Y coordinate to $46 and draw.
    ;
    moveq   #70,D0
    cmpi.b  #$0F,D2
    beq  _L_z05_DrawSubmenuItems_Draw
    cmpi.b  #$09,D2
    bcs  _L_z05_DrawSubmenuItems_Draw
    ; If the item goes in the unselectable row at the top (item slot < $10),
    ; then go set Y coordinate to $1E and draw.
    ;
    moveq   #30,D0
    cmpi.b  #$10,D2
    bcs  _L_z05_DrawSubmenuItems_Draw
    ; The Y coordinate of the compass is $9E; and the map's is $76.
    ; The X coordinate for both is $2C.
    ;
    moveq   #44,D0
    move.b  D0,($0000,A4)
    move.b  #$9E,D0
    cmpi.b  #$11,D2
    bcs  _L_z05_DrawSubmenuItems_Draw
    moveq   #118,D0
    even
_L_z05_DrawSubmenuItems_Draw:
    move.b  D0,($0001,A4)
    jsr     DrawItemInInventoryWithX
    move.b  (A5)+,D0  ; PLA
    moveq   #0,D2
    move.b  D0,D2
    even
_L_z05_DrawSubmenuItems_NextLoopDrawItem:
    ; Loop until item slot = $12.
    ;
    addq.b  #1,D2
    cmpi.b  #$12,D2
    bcs  _L_z05_DrawSubmenuItems_LoopDrawItem
    rts

    even
SubmenuCursorXs:
    dc.b    $80, $98, $B0, $B0, $C8, $80, $98, $B0
    dc.b    $C8

    even
UpdateSubmenuSelection:
    ; Pseudo-item slot 0 is for boomerangs.
    ; If it's not the currently selected item slot, then skip this.
    ;
    moveq   #0,D2
    move.b  ($0656,A4),D2
    bne  _L_z05_UpdateSubmenuSelection_DrawBreakoutItem
    ; Look for a magic boomerang, then a wooden boomerang.
    ; If you find one, then use its item slot.
    ;
    moveq   #30,D2
_anon_z05_212:
    lea     ($0657,A4),A0
    move.b  (A0,D2.W),D0
    bne  _L_z05_UpdateSubmenuSelection_DrawBreakoutItem
    subq.b  #1,D2
    cmpi.b  #$1C,D2
    bne  _anon_z05_212
    beq  _L_z05_UpdateSubmenuSelection_AfterBreakoutItem
    even
_L_z05_UpdateSubmenuSelection_DrawBreakoutItem:
    ; Draw the item in the box for the currently selected item,
    ; if we have it.
    ;
    ; There's also the special case for the letter. If the selected item
    ; is the letter, but we have a potion, then skip this.
    ;
    ; If the letter is selected and there's no potion, then make
    ; the item value 1 in [04]. Except that, the call to 05:B81C
    ; below will overwrite [04].
    ;
    lea     ($0657,A4),A0
    move.b  (A0,D2.W),D0
    beq  _L_z05_UpdateSubmenuSelection_AfterBreakoutItem
    cmpi.b  #$0F,D2
    bne  _anon_z05_213
    move.b  ($065E,A4),D0
    bne  _L_z05_UpdateSubmenuSelection_AfterBreakoutItem
    moveq   #1,D0
_anon_z05_213:
    move.b  D0,($0004,A4)
    moveq   #54,D0
    move.b  D0,($0001,A4)
    moveq   #64,D0
    move.b  D0,($0000,A4)
    jsr     DrawItemInInventoryWithX
    even
_L_z05_UpdateSubmenuSelection_AfterBreakoutItem:
    ; If the selected item slot is the letter's and we have potions,
    ; then select the potion item slot.
    ;
    moveq   #0,D3
    move.b  ($0656,A4),D3
    cmpi.b  #$0F,D3
    bne  _L_z05_UpdateSubmenuSelection_DrawCursor
    moveq   #7,D3
    lea     ($0657,A4),A0
    move.b  (A0,D3.W),D0
    beq  _L_z05_UpdateSubmenuSelection_DrawCursor
    move.b  D3,($0656,A4)
    even
_L_z05_UpdateSubmenuSelection_DrawCursor:
    ; Look up the X coordinate for the selected item slot.
    ; Set it for the left cursor sprite.
    ; Then add 8 to set the right cursor sprite's X.
    ;
    lea     (SubmenuCursorXs).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($021F,A4)
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$08,D1
    addx.b  D1,D0   ; ADC #$08 (X flag = 6502 C)
    move.b  D0,($0223,A4)
    ; The Y coordinate is $36 for item slots < 5, else $46.
    ;
    moveq   #54,D0
    cmpi.b  #$05,D3
    bcs  _anon_z05_214
    moveq   #70,D0
_anon_z05_214:
    move.b  D0,($021C,A4)
    move.b  D0,($0220,A4)
    ; $1E is the cursor tile.
    ;
    moveq   #30,D0
    move.b  D0,($021D,A4)
    move.b  D0,($0221,A4)
    ; Flash the cursor.
    ; Use palette rows 5 and 6 for 8 frames each.
    ;
    move.b  ($0015,A4),D0
    andi.b #$08,D0
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    move.b  #$01,D1
    addx.b  D1,D0   ; ADC #$01 (X flag = 6502 C)
    move.b  D0,($021E,A4)
    ; Flip the right sprite horizontally.
    ;
    ori.b #$40,D0
    move.b  D0,($0222,A4)
    ; TODO:
    ; If input direction = [EF] item search direction in the previous frame, return.
    ;
    move.b  ($03F8,A4),D0
    move.b  ($00EF,A4),D1
    cmp.b   D1,D0
    bne.s  __far_z_05_0130
    jmp  L177F1_Exit
__far_z_05_0130:
    moveq   #0,D2
    move.b  D0,D2
    ; If input direction = 0, up, or down; then we won't change
    ; the change the selected item slot forward or backward.
    ;
    ; Instead, jump to this routine to make sure an occupied slot
    ; is selected, then return.
    ;
    bne.s  __far_z_05_0131
    jmp  FindAndSelectOccupiedItemSlot
__far_z_05_0131:
    cmpi.b  #$04,D2
    bcs.s  __far_z_05_0132
    jmp  FindAndSelectOccupiedItemSlot
__far_z_05_0132:
    ; Cue the "selection changed" tune.
    ;
    moveq   #1,D2
    move.b  D2,($0602,A4)
    ; Move the selection in the input direction.
    ;
    ;
    ; Save the input direction.
    moveq   #0,D2
    move.b  D0,D2
    move.b  ($0656,A4),D0
    move.b  D0,-(A5)  ; PHA
    move.b  D2,D0
    jsr     FindAndSelectOccupiedItemSlot
    ; If the new item slot = old item slot, go cancel the
    ; "selection changed" tune.
    ;
    ;
    ; Pop selected item slot.
    move.b  (A5)+,D0  ; PLA
    move.b  ($0656,A4),D1
    cmp.b   D1,D0
    beq  _L_z05_UpdateSubmenuSelection_CancelTune
    ; Else the selection changed. The new slot should have an item.
    ; If it does not, then cancel the "selection changed" tune.
    ;
    moveq   #0,D3
    move.b  ($0656,A4),D3
    lea     ($0657,A4),A0
    move.b  (A0,D3.W),D0
    bne  _anon_z05_215
    even
_L_z05_UpdateSubmenuSelection_CancelTune:
    move.b  ($0602,A4),D1
    lsr.b  #1,D1   ; LSR Tune1Request
    move.b  D1,($0602,A4)
_anon_z05_215:
    rts

; Params:
; A: direction to search: 0=none, 1=forward, 2=backward
; Y: starting item slot
;
; Returns:
; [EF]: direction to search
;
    even
FindAndSelectOccupiedItemSlot:
    move.b  D0,($00EF,A4)
    moveq   #9,D2
    even
LoopItemSlot:
    jsr     Cycle9InDirection
    cmpi.b  #$00,D3
    bne.s  __far_z_05_0133
    jmp  CheckBoomerangs
__far_z_05_0133:
    cmpi.b  #$03,D3
    bne.s  __far_z_05_0134
    jmp  CheckNextItem
__far_z_05_0134:
    lea     ($0657,A4),A0
    move.b  (A0,D3.W),D0
    beq.s  __far_z_05_0135
    jmp  FoundSlot
__far_z_05_0135:
    cmpi.b  #$07,D3
    bne.s  __far_z_05_0136
    jmp  CheckLetter
__far_z_05_0136:
    even
CheckNextItem:
    subq.b  #1,D2
    bmi.s  __far_z_05_0137
    jmp  LoopItemSlot
__far_z_05_0137:
    moveq   #0,D3
    even
FoundSlot:
    cmpi.b  #$02,D3
    beq.s  __far_z_05_0138
    jmp  SetSlotFound
__far_z_05_0138:
    move.b  ($065A,A4),D0
    bne.s  __far_z_05_0139
    jmp  LoopItemSlot
__far_z_05_0139:
    even
SetSlotFound:
    move.b  D3,($0656,A4)
    even
L177F1_Exit:
    rts

    even
CheckBoomerangs:
    ; Check the boomerangs.
    ;
    ; Start with the magical boomerang.
    moveq   #30,D3
_anon_z05_216:
    lea     ($0657,A4),A0
    move.b  (A0,D3.W),D0
    bne  _anon_z05_217
    subq.b  #1,D3
    cmpi.b  #$1C,D3
    bne  _anon_z05_216
    moveq   #0,D3
    jmp     CheckNextItem

_anon_z05_217:
    moveq   #0,D3
    jmp     FoundSlot

    even
CheckLetter:
    ; Check the letter.
    ;
    moveq   #15,D3
    lea     ($0657,A4),A0
    move.b  (A0,D3.W),D0
    bne  _anon_z05_218
    moveq   #7,D3
    beq.s  __far_z_05_0140
    jmp  CheckNextItem
__far_z_05_0140:
_anon_z05_218:
    move.b  ($065E,A4),D0
    bne.s  __far_z_05_0141
    jmp  SetSlotFound
__far_z_05_0141:
    moveq   #7,D3
    beq.s  __far_z_05_0142
    jmp  SetSlotFound
__far_z_05_0142:
    even
DrawItemInInventoryWithX:
    ; [$00]: X
    ; [$01]: Y
    ; X: item slot
    ;
    move.b  D2,D0
    moveq   #0,D3
    move.b  D0,D3
    jmp     DrawItemInInventory

; Params:
; [$EF]: direction to search: 0=none, 1=forward, 2=backward
; Y: value to cycle
;
; If A = 0, does nothing.
; If A = 1, Y := (Y + 1) mod 9
; If A = 2, Y := (Y - 1) mod 9
;
    even
Cycle9InDirection:
    move.b  ($00EF,A4),D0
    andi.b #$03,D0
    beq  _L_z05_Cycle9InDirection_Exit
    addq.b  #1,D3
    lsr.b  #1,D0   ; LSR A
    bcs  _anon_z05_219
    subq.b  #1,D3
    subq.b  #1,D3
_anon_z05_219:
    cmpi.b  #$FF,D3
    bne  _anon_z05_220
    moveq   #8,D3
_anon_z05_220:
    cmpi.b  #$09,D3
    bne  _L_z05_Cycle9InDirection_Exit
    moveq   #0,D3
    even
_L_z05_Cycle9InDirection_Exit:
    rts

    even
CreateRoomObjects:
    ; Reset ObjState[$13] to activate room item object.
    ;
    moveq   #0,D0
    move.b  D0,($00BF,A4)
    ; If in OW, go create heart container in room 5F.
    ;
    move.b  ($0010,A4),D0
    beq  _L_z05_CreateRoomObjects_MakeHeartContainerOW
    ; If the player got the room item already, go deactivate
    ; the room item object.
    ;
    jsr     GetRoomFlagUWItemState
    bne  _L_z05_CreateRoomObjects_Deactivate
    ; Look up the item for this room, and store it.
    ; If it's item ID 3, then deactivate the object.
    ;
    ; Item ID 3 normally means the master sword. But because the
    ; usual value meaning "no item" ($3F) can't fit in the level
    ; block attribute for a room item (up to $1F); use 3 to
    ; stand in for it.
    ;
    moveq   #0,D3
    move.b  ($00EB,A4),D3
    lea     (NES_SRAM+$0A7E).l,A0
    move.b  (A0,D3.W),D0
    andi.b #$1F,D0
    cmpi.b  #$03,D0
    bne  _anon_z05_221
    subq.b  #1,($00BF,A4)
_anon_z05_221:
    move.b  D0,($00AB,A4)
    ; If secret trigger is 3 "last boss" or 7 "foes for item",
    ; then deactivate room item object. They'll be activated by
    ; the secret action.
    ;
    lea     (NES_SRAM+$0AFE).l,A0
    move.b  (A0,D3.W),D0
    andi.b #$07,D0
    cmpi.b  #$03,D0
    beq  _L_z05_CreateRoomObjects_Deactivate
    cmpi.b  #$07,D0
    bne  _anon_z05_222
    even
_L_z05_CreateRoomObjects_Deactivate:
    subq.b  #1,($00BF,A4)
_anon_z05_222:
    ; If there's a push block in the room, then look for where
    ; it goes, and activate it.
    ;
    lea     (NES_SRAM+$09FE).l,A0
    move.b  (A0,D3.W),D0
    andi.b #$40,D0
    beq  _anon_z05_223
    jsr     FindAndCreatePushBlockObject
_anon_z05_223:
    ; Set the X and Y for the room item object.
    ;
    jsr     GetShortcutOrItemXY
    even
_L_z05_CreateRoomObjects_StoreLocation:
    move.b  D0,($0083,A4)
    move.b  D3,($0097,A4)
    ; If the room item is a triforce piece,
    ; the move it left 8 pixels.
    moveq   #0,D3
    move.b  ($00EB,A4),D3
    lea     (NES_SRAM+$0A7E).l,A0
    move.b  (A0,D3.W),D0
    andi.b #$1F,D0
    cmpi.b  #$1B,D0
    bne  _anon_z05_224
    move.b  ($0083,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$08,D1
    eori    #$10,CCR  ; flip X: 6502 SBC polarity
    subx.b  D1,D0   ; SBC #$08
    eori    #$10,CCR  ; restore X = 6502 C
    move.b  D0,($0083,A4)
_anon_z05_224:
    eori    #$01,CCR  ; normalize C to 6502 polarity before RTS
    rts

    even
_L_z05_CreateRoomObjects_MakeHeartContainerOW:
    ; Try to make the heart container in OW.
    ;
    ;
    ; Heart container
    moveq   #26,D0
    move.b  D0,($00AB,A4)
    ; Load the coordinates of the heart container in
    ; OW room $5F.
    ;
    move.b  #$C0,D0
    move.b  #$90,D3
    ; If in mode 5, and in room $5F, then go store the coordinates
    ; in the object slot.
    ;
    moveq   #0,D2
    move.b  ($0012,A4),D2
    cmpi.b  #$05,D2
    bne  _anon_z05_225
    moveq   #0,D2
    move.b  ($00EB,A4),D2
    cmpi.b  #$5F,D2
    beq  _L_z05_CreateRoomObjects_StoreLocation
_anon_z05_225:
    ; Else deactivate the object.
    ;
    subq.b  #1,($00BF,A4)
    rts


