    lsr.b  #1,D0   ; LSR A
    jsr     _mmc1_write_8000  ; MMC1 reg write, D0=val
    lsr.b  #1,D0   ; LSR A
    jsr     _mmc1_write_8000  ; MMC1 reg write, D0=val
    rts

